async function api(path,options={}){
  let response;
  try{response=await fetch(path,{...options,credentials:"same-origin",headers:{"Content-Type":"application/json",...(options.headers||{})}});}catch(error){if(window.demoApi)return window.demoApi(path,options);throw error;}
  if(response.status===404&&window.demoApi)return window.demoApi(path,options);
  const payload=await response.json().catch(()=>({}));
  if(!response.ok){const error=new Error(payload.error?.message||`请求失败 (${response.status})`);error.status=response.status;throw error;}
  return payload.data;
}
function roleCan(...roles){return Boolean(currentUser&&roles.includes(currentUser.role));}
function showLogin(message=""){document.getElementById("app").classList.add("hidden");document.getElementById("loginScreen").classList.remove("hidden");document.getElementById("loginError").textContent=message;}
function enterApp(user){currentUser=user;document.getElementById("loginScreen").classList.add("hidden");document.getElementById("app").classList.remove("hidden");document.getElementById("accountButton").textContent=user.username.slice(0,1).toUpperCase();render();}
async function loadData(){
  try{
    const baseRequests=[api("/api/v1/payment-orders"),api("/api/v1/withdrawals"),api("/api/v1/transactions"),api("/api/v1/callbacks"),api("/api/v1/demo-merchant/webhooks"),api("/api/v1/withdrawal-events"),api("/api/v1/reconciliation"),api("/api/v1/risk-policy"),api("/api/v1/network-reserves"),api("/api/v1/network-fee-events"),api("/api/v1/collections"),api("/api/v1/collection-candidates"),api("/api/v1/collection-policy"),api("/api/v1/address-book"),api("/api/v1/ip-allowlist"),api("/api/v1/project-settings"),api("/api/v1/demo-readiness")];
    const [payments,withdrawals,transactions,callbacks,webhookReceipts,events,reconciliation,riskPolicy,networkReserves,networkFeeEvents,collections,collectionCandidates,collectionPolicy,addressBook,ipAllowlist,projectSettings,readiness]=await Promise.all(baseRequests);
    const auditLogs=roleCan("ADMIN","FINANCE")?await api("/api/v1/audit-logs"):[];
    const apiKeys=roleCan("ADMIN")?await api("/api/v1/api-keys"):[];
    data={payments,withdrawals,transactions,callbacks,webhookReceipts,events,reconciliation,riskPolicy,networkReserves,networkFeeEvents,collections,collectionCandidates,collectionPolicy,addressBook,ipAllowlist,projectSettings,readiness,auditLogs,apiKeys};render();
  }catch(error){if(error.status===401){showLogin("登录已失效，请重新登录");return;}toast(`后端连接失败：${error.message}`);render();}
}
async function bootstrap(){
  try{const user=await api("/api/v1/session");enterApp(user);await loadData();}
  catch(error){showLogin(error.status===401?"":"服务暂时不可用");}
}
function esc(v){return String(v??"").replace(/[&<>'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"})[c]);}
function short(v,h=7,t=5){return v?`${v.slice(0,h)}...${v.slice(-t)}`:"—";}
function amount(v){return Number(v||0).toLocaleString("zh-CN",{minimumFractionDigits:2,maximumFractionDigits:6});}
function time(v){return v?new Date(v).toLocaleString("zh-CN",{month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit"}):"—";}
function status(v){const map={PENDING:"待支付",PARTIAL:"Underpaid",OVERPAID:"Overpaid",EXPIRED:"Expired",PENDING_APPROVAL:"待审批",APPROVED:"已审批",SIGNING:"待签名",BROADCASTED:"广播中",CONFIRMED:"已完成",REJECTED:"已拒绝",FAILED:"失败",DELIVERED:"已送达",SKIPPED:"已忽略"};const bad=["FAILED","REJECTED","EXPIRED"].includes(v),pending=["PENDING","PARTIAL","PENDING_APPROVAL","APPROVED","SIGNING","BROADCASTED"].includes(v);return `<span class="status ${bad?'failed':pending?'pending':''}">${map[v]||v}</span>`;}
function empty(label="暂无数据"){return `<div class="empty"><div><span>◇</span>${label}</div></div>`;}
function toast(message){const el=document.getElementById("toast");el.textContent=message;el.classList.add("show");clearTimeout(window.toastTimer);window.toastTimer=setTimeout(()=>el.classList.remove("show"),2600);}

function render(){
  document.getElementById("primaryNav").innerHTML=modules.map(([id,icon,label])=>`<button class="rail-item ${ui.module===id?'active':''}" data-module="${id}"><span>${icon}</span>${label}${id==='waas'&&data.callbacks.filter(x=>x.status==='FAILED').length?`<b>${data.callbacks.filter(x=>x.status==='FAILED').length}</b>`:''}</button>`).join("");
  document.getElementById("subnav").innerHTML=renderSubnav();
  document.getElementById("workspace").innerHTML=renderWorkspace();
  if(!roleCan("ADMIN","OPERATOR"))document.querySelectorAll('[data-action="create-payment"],[data-retry]').forEach(el=>el.remove());
}
function subButton(id,icon,label,count=""){return `<button class="sub-item ${ui.page===id?'active':''}" data-page="${id}"><span class="sub-icon">${icon}</span>${label}${count!==""?`<span class="sub-count">${count}</span>`:""}</button>`;}
function renderSubnav(){
  if(ui.module==="wallet")return `<div class="sub-head">钱包<button data-action="new-wallet">＋</button></div><div class="wallet-list">${demoWallets.map(w=>`<button class="wallet-row ${ui.wallet===w.name?'active':''}" data-wallet="${w.name}"><strong>${w.name}</strong><small><span>${w.type}</span><span>分片 ◉</span></small><b>${w.balance}</b></button>`).join("")}</div>`;
  if(ui.module==="workflow")return `<div class="sub-head">协作</div><div class="sub-section-title">待办</div>${subButton('pending-approval','◌','待审批',data.withdrawals.filter(x=>x.status==='PENDING_APPROVAL').length)}${subButton('pending-sign','◇','待签名',data.withdrawals.filter(x=>['APPROVED','SIGNING'].includes(x.status)).length)}<div class="sub-section-title">已办</div>${subButton('approved','✓','已审批')}${subButton('signed','✎','已签名')}<div class="sub-section-title"></div>${subButton('all-workflow','☷','全部')}${subButton('initiated','↗','我发起的')}`;
  if(ui.module==="waas")return `<div class="sub-head">M2 Pay 项目⌄</div><div class="sub-section-title">提币记录</div>${subButton('waas-payout','▣','钱包提币',data.withdrawals.length)}<div class="sub-section-title">回调记录</div>${subButton('waas-error','!','异常回调',data.callbacks.filter(x=>x.status==='FAILED').length)}${subButton('waas-history','↻','历史回调',data.callbacks.length)}<div class="sub-section-title"></div>${subButton('waas-settings','⚙','设置')}`;
  if(ui.module==="payment"&&ui.page!=='landing')return `<div class="sub-head">M2 收付项目⌄</div><div class="sub-section-title">收款</div>${subButton('payment-orders','▤','支付订单',data.payments.length)}<div class="sub-section-title">结算</div>${subButton('payment-settlements','⇄','结算记录')}${subButton('payment-settings','⚙','设置')}`;
  if(ui.module==="risk")return `<div class="sub-head">风控</div>${subButton('strategy','◇','策略')}${subButton('automation','↻','自动化')}${subButton('aml','◉','AML')}${subButton('risk-log','▤','日志')}<div class="sub-section-title">地址簿</div>${subButton('whitelist','✓','白名单')}${subButton('blacklist','×','黑名单')}`;
  if(ui.module==="management")return `<div class="sub-head">管理</div>${subButton('demo-acceptance','✓','Demo Acceptance',`${data.readiness.passed}/${data.readiness.total}`)}${subButton('subscription','▧','团队订阅')}${subButton('account','◉','团队账户')}${subButton('orders','▤','订单管理')}${subButton('members','♙','成员')}${subButton('roles','♧','角色')}${subButton('security','▣','团队安全')}${subButton('team-api','{ }','团队API')}${roleCan('ADMIN','FINANCE')?subButton('audit','▤','审计日志',data.auditLogs.length):''}`;
  if(ui.module==="settings")return `<div class="sub-head">账号设置</div>${subButton('preference','◇','偏好设置')}${subButton('account-security','▣','账号安全')}${subButton('mpc-network','◎','MPC网络')}${subButton('about','◉','关于 M2 Wallet')}`;
  return `<div class="sub-head">${roleSubtitles[ui.module]}</div>`;
}
function renderWorkspace(){
  if(ui.module==="wallet"&&ui.page==="wallet-receive")return walletReceivePage();
  if(ui.module==="wallet"&&ui.page==="wallet-send")return walletSendPage();
  if(ui.module==="wallet"&&ui.page==="wallet-transactions")return walletTransactionsPage();
  if(ui.module==="wallet")return walletPage();
  if(ui.module==="workflow")return workflowPage();
  if(ui.module==="waas")return waasPage();
  if(ui.module==="payment")return paymentPageV2();
  if(ui.module==="transactions")return transactionsPage();
  if(ui.module==="risk"&&ui.page==="strategy")return riskStrategyPageV2();
  if(ui.module==="risk"&&ui.page==="automation")return automationPageV2();
  if(ui.module==="risk")return riskPage();
  if(ui.module==="management"&&ui.page==="demo-acceptance")return demoAcceptancePage();
  if(ui.module==="management"&&ui.page==="audit")return auditPage();
  if(ui.module==="management"&&ui.page==="roles")return rolesPageV2();
  if(ui.module==="management")return managementPage();
  if(ui.module==="settings")return accountSettingsPageV2();
  return marketPage();
}

function assetFlowStats(symbol){const orders=data.payments.filter(p=>p.pay_currency===symbol),processing=orders.filter(p=>p.status==='PENDING').reduce((s,p)=>s+Number(p.amount||0),0),collectable=data.collectionCandidates.filter(c=>c.asset===symbol).reduce((s,c)=>s+Number(c.amount||0),0);return {processing,collectable};}
function walletPage(){return `<section class="page wallet-page"><div class="page-head"><span>▣</span><div class="head-actions"><button class="circle-action" data-action="send" ${roleCan('ADMIN','OPERATOR')?'':'disabled'}><i>↑</i>发送</button><button class="circle-action" data-action="receive"><i>↓</i>接收</button><button class="circle-action" data-action="addresses"><i>▣</i>地址</button></div></div><div class="asset-total"><strong>${demoWallets.find(w=>w.name===ui.wallet)?.balance||'$ 0'}</strong><small>总资产</small></div><div class="tabs"><button class="tab active">币种</button><button class="tab" data-action="wallet-transactions">交易记录</button></div><div>${assets.map(asset=>{const flow=assetFlowStats(asset.symbol);return `<div class="asset-row" data-asset="${asset.symbol}"><span class="coin ${asset.symbol.toLowerCase()}">${asset.symbol==='USDT'?'₮':asset.symbol==='USDC'?'$':asset.symbol[0]}</span><div class="asset-name"><strong>${asset.symbol}${asset.chains.length>1?'　<small>多链</small>':''}</strong><small>${asset.name}</small><div class="asset-stats">${asset.amount} 可用　|　${amount(flow.processing)} 处理中　|　${amount(flow.collectable)} 可归集</div></div><div class="asset-amount"><strong>${asset.amount}</strong><small>≈ ${asset.usd}</small></div>${ui.assetExpanded===asset.symbol?`<div class="chain-detail">${asset.chains.map((c,i)=>`<div class="chain-pill"><b>${c}</b>${i===0?asset.amount:'0'} 可用<br>${i===0?amount(flow.processing):'0'} 处理中　${i===0?amount(flow.collectable):'0'} 可归集</div>`).join('')}</div>`:''}</div>`}).join('')}</div>${ui.walletDrawer==='addresses'?walletAddressDrawer():''}</section>`;}

function coinMark(symbol){return `<span class="coin ${symbol.toLowerCase()}">${symbol==='USDT'?'₮':symbol==='USDC'?'$':symbol[0]}</span>`;}
function flowCoinList(action){return `<div class="flow-search">⌕ <input placeholder="搜索币种"/></div><div class="flow-list">${assets.map(a=>`<button class="flow-choice" data-${action}-coin="${a.symbol}">${coinMark(a.symbol)}<span><b>${a.symbol}</b><small>${a.name}</small></span><i>›</i></button>`).join('')}</div>`;}
function flowNetworks(symbol,action){const asset=assets.find(a=>a.symbol===symbol);return `<div class="flow-list network-list">${(asset?.chains||[]).map(n=>`<button class="flow-choice" data-${action}-network="${n}"><span class="network-mark">${n==='TRON'?'◆':n==='Ethereum'?'◇':'⬡'}</span><span><b>${n}</b><small>${symbol} · ${n}</small></span><i>›</i></button>`).join('')}</div>`;}
function flowHeader(title){return `<div class="flow-title"><button data-action="wallet-back">‹</button><h1>${title}</h1></div>`;}
function completeStep(num,title,summary,reset){return `<div class="flow-step complete"><span class="step-dot">✓</span><div><h3>${title}</h3><div class="selected-summary">${summary}</div></div><button class="step-reset" data-action="${reset}">×</button></div>`;}
function qrGrid(){let cells='';for(let i=0;i<441;i++){const on=i<63||(i%21>13&&i<147)||((i*13+i%7)%5<2);cells+=`<i class="${on?'on':''}"></i>`;}return `<div class="qr-grid" aria-label="模拟二维码">${cells}</div>`;}
function walletReceivePage(){const coin=ui.receiveCoin,network=ui.receiveNetwork;const address=coin&&network?`M2-DEMO-${coin}-${network.replace(/\s/g,'-').toUpperCase()}-NOT-A-REAL-ADDRESS`:'';return `<section class="page wallet-flow">${flowHeader('接收')}<div class="flow-body">${coin?completeStep(1,'币种',`${coinMark(coin)}<b>${coin}</b><small>${assets.find(a=>a.symbol===coin)?.name||''}</small>`,'receive-reset-coin'):`<div class="flow-step current"><span class="step-dot">1</span><div><h3>币种</h3>${flowCoinList('receive')}</div></div>`}${coin?(network?completeStep(2,'网络',`<span class="network-mark">${network==='TRON'?'◆':'⬡'}</span><b>${network}</b>`,'receive-reset-network'):`<div class="flow-step current"><span class="step-dot">2</span><div><h3>网络</h3>${flowNetworks(coin,'receive')}</div></div>`):`<div class="flow-step muted"><span class="step-dot">2</span><h3>网络</h3></div>`}${coin&&network?`<div class="flow-step current address-step"><span class="step-dot">3</span><div><h3>地址</h3><div class="receive-card">${qrGrid()}<div class="address-copy"><small>${coin} 地址</small><strong>${address}</strong><button class="btn primary" data-copy="${address}">复制</button></div></div><p class="flow-tip">● 该地址仅用于 ${coin} 收款，勿用于其他币种。演示地址不可用于真实转账。</p></div></div>`:`<div class="flow-step muted"><span class="step-dot">3</span><h3>地址</h3></div>`}</div></section>`;}
function walletSendPage(){const coin=ui.sendCoin,network=ui.sendNetwork,demoAddress=network==='TRON'?'TCGrXtAjSDfUV2xxNEgaui28odN6MdyHun':network==='Polygon'?'0xcee5bda9569f39eb9657472c4f8d5290f58653ad':'';return `<section class="page wallet-flow">${flowHeader('发送')}<div class="flow-body">${coin?completeStep(1,'币种',`${coinMark(coin)}<b>${coin}</b><small>${assets.find(a=>a.symbol===coin)?.name||''}</small>`,'send-reset-coin'):`<div class="flow-step current"><span class="step-dot">1</span><div><h3>币种</h3>${flowCoinList('send')}</div></div>`}${coin?(network?completeStep(2,'网络',`<span class="network-mark">${network==='TRON'?'◆':'⬡'}</span><b>${network}</b>`,'send-reset-network'):`<div class="flow-step current"><span class="step-dot">2</span><div><h3>网络</h3>${flowNetworks(coin,'send')}</div></div>`):`<div class="flow-step muted"><span class="step-dot">2</span><h3>网络</h3></div>`}${coin&&network?`<div class="flow-step current"><span class="step-dot">3</span><div class="send-form"><h3>接收方地址</h3><input id="sendAddress" value="${demoAddress}" placeholder="输入或粘贴地址"/><h3>4　输入交易金额</h3><div class="amount-input"><input id="sendAmount" value="100.00" placeholder="0.00"/><b>${coin}</b></div><small>可用 ${assets.find(a=>a.symbol===coin)?.amount||0} ${coin}　·　当前为模拟资金模式</small><button class="btn primary send-next" data-action="demo-send-inline">提交财务审批</button></div></div>`:`<div class="flow-step muted"><span class="step-dot">3</span><h3>接收方地址</h3></div><div class="flow-step muted"><span class="step-dot">4</span><h3>输入交易金额</h3></div>`}</div></section>`;}
function walletAddressDrawer(){return `<div class="drawer-mask" data-action="close-wallet-drawer"></div><aside class="wallet-drawer address-drawer"><button class="drawer-close" data-action="close-wallet-drawer">×</button><button class="coin-select">${coinMark('BTC')}<b>BTC</b><span>Bitcoin</span><i>⌄</i></button><div class="drawer-search">⌕ <input placeholder="地址、别名"/><button title="添加地址">＋</button></div><div class="address-entry"><strong>未命名的地址</strong><div><span class="tag orange">★ 默认付款</span><span class="tag green">★ 默认收款</span></div><code>M2-DEMO-BTC-NOT-A-REAL-ADDRESS</code><small>0 可用　|　0 处理中</small></div></aside>`;}
function walletTxRows(){const rows=data.transactions.length?data.transactions.slice(0,8):[{id:'TX-DEMO-001',asset:'TRX',network:'TRON',direction:'IN',amount:'0.000005',status:'CONFIRMED',address:'M2-DEMO-TRON-ADDRESS',tx_hash:'M2-DEMO-HASH',updated_at:new Date().toISOString()}];return rows;}
function walletTransactionsPage(){const rows=walletTxRows();return `<section class="page wallet-page"><div class="page-head"><span>▣</span><div class="head-actions"><button class="circle-action" data-action="send" ${roleCan('ADMIN','OPERATOR')?'':'disabled'}><i>↑</i>发送</button><button class="circle-action" data-action="receive"><i>↓</i>接收</button><button class="circle-action" data-action="addresses"><i>▣</i>地址</button></div></div><div class="asset-total"><strong>${demoWallets.find(w=>w.name===ui.wallet)?.balance||'$ 0'}</strong><small>总资产</small></div><div class="tabs"><button class="tab" data-action="wallet-assets">币种</button><button class="tab active">交易记录</button></div><div class="wallet-tx-tools"><div><button class="btn active">历史记录</button><button class="btn">处理中</button></div><div><button class="btn">↻ 刷新</button><button class="btn">▽ 筛选</button><button class="btn">显示⌄</button><button class="btn">排序⌄</button></div></div><div class="wallet-tx-list">${rows.map((t,i)=>`<button class="wallet-tx-row" data-wallet-tx="${i}">${coinMark(t.asset)}<span><b>${t.direction==='OUT'?'发送':'接收'}</b><small>发送方：${short(t.direction==='OUT'?t.address:'M2-DEMO-SENDER',12,8)}</small><small>接收方：${short(t.direction==='OUT'?'M2-DEMO-RECEIVER':t.address,12,8)}</small><em>${time(t.updated_at)}</em></span><strong>${t.direction==='OUT'?'-':'+'}${amount(t.amount)} ${t.asset}<small>≈ $ ${Number(t.amount||0).toFixed(2)}</small><small>矿工费 0 ${t.asset}</small></strong></button>`).join('')}</div>${ui.walletTx!==''?walletTxDrawer(rows[Number(ui.walletTx)]):''}</section>`;}
function walletTxDrawer(t){if(!t)return'';const incoming=t.direction!=='OUT';return `<div class="drawer-mask" data-action="close-tx-drawer"></div><aside class="wallet-drawer tx-drawer"><button class="drawer-close" data-action="close-tx-drawer">×</button><div class="tx-hero">${coinMark(t.asset)}<small>${incoming?'接收':'发送'} ${t.asset}</small><h2>${incoming?'+':'-'} ${amount(t.amount)}</h2><b>成功</b></div><div class="tx-fields"><label>发送方<strong>${incoming?'M2-DEMO-SENDER':(t.address||'M2-DEMO-SENDER')}</strong></label><label>接收方<strong>${incoming?(t.address||'M2-DEMO-RECEIVER'):'M2-DEMO-RECEIVER'}</strong></label><label>矿工费<strong>0 ${t.asset}</strong></label><label>交易时间<strong>${time(t.updated_at)}</strong></label><label>交易哈希<strong>${t.tx_hash||'M2-DEMO-TRANSACTION-HASH'}</strong></label><label>备注<strong>暂无备注</strong></label></div><button class="receipt-btn">下载交易凭证</button></aside>`;}

function workflowPage(){
  const mode=ui.page||'pending-approval';let items=data.withdrawals;
  if(mode==='pending-approval')items=items.filter(x=>x.status==='PENDING_APPROVAL');if(mode==='pending-sign')items=items.filter(x=>['APPROVED','SIGNING'].includes(x.status));if(mode==='approved')items=items.filter(x=>['APPROVED','BROADCASTED','CONFIRMED','REJECTED'].includes(x.status));if(mode==='signed')items=items.filter(x=>['BROADCASTED','CONFIRMED'].includes(x.status));
  const title=({"pending-approval":"待审批","pending-sign":"待签名",approved:"已审批",signed:"已签名",initiated:"我发起的","all-workflow":"全部"})[mode]||'待审批';
  return `<section class="page workflow-page"><div class="workflow-toolbar"><div class="filter-bar"><input placeholder="发送方、接收方"/><input type="date"/><span>–</span><input type="date"/><button class="icon-filter">▽</button></div></div>${items.length?`<div class="workflow-native-list">${items.map((w,i)=>`<button class="workflow-native-row" data-workflow-item="${w.id}">${coinMark(w.currency)}<span><b>${esc(w.merchant)} <small>单签</small></b><em>申请向【 ${short(w.to_address,7,6)} 】付款 ${amount(w.amount)} ${w.currency}-${w.network==='TRON'?'TRC20':w.network}</em><time>${time(w.created_at)}</time></span><strong>${w.status==='CONFIRMED'?'自动签名':w.status==='PENDING_APPROVAL'?'待审批':w.status==='REJECTED'?'已拒绝':'处理中'}</strong></button>`).join('')}</div>`:empty(mode==='pending-approval'?'暂无待处理事务':'暂无相关业务数据')}${ui.workflowItem?workflowDetailDrawer(items.find(x=>x.id===ui.workflowItem)||data.withdrawals.find(x=>x.id===ui.workflowItem)):''}</section>`;
}
function workflowDetailDrawer(w){if(!w)return'';const done=w.status==='CONFIRMED',pending=w.status==='PENDING_APPROVAL',validation=data.events.find(e=>e.withdrawal_id===w.id&&e.status==='EXTERNAL_VALIDATION'),verificationEnabled=data.projectSettings?.withdrawal_verification_enabled,reserve=(data.networkReserves||[]).find(r=>r.network===w.network),reserveReady=Boolean(reserve?.healthy);return `<div class="drawer-mask"></div><aside class="wallet-drawer workflow-drawer"><button class="drawer-close" data-action="close-workflow-drawer">×</button><div class="tx-hero">${coinMark(w.currency)}<small>${esc(w.merchant)} - 申请付款 ${w.currency}-${w.network==='TRON'?'TRC20':w.network}</small><h2>${amount(w.amount)}</h2><b>${done?'自动签名':pending?'待审批':w.status==='REJECTED'?'已拒绝':'处理中'}</b></div><div class="approval-evidence ${reserveReady?'ready':'blocked'}"><span>${reserveReady?'✓':'!'}</span><div><b>${esc(w.network)} network fee reserve</b><small>${reserve?`${amount(reserve.available)} ${esc(reserve.native_asset)} available · ${reserve.projected_transactions} projected transactions`:'Reserve data unavailable'}</small></div><strong>${reserveReady?'Ready':'Blocked'}</strong></div><div class="tx-fields"><label>发送方<strong>M2-DEMO-SENDER-ADDRESS</strong></label><label>接收方<strong>${esc(w.to_address)}</strong></label><label>付款钱包<strong>${esc(w.merchant)} · ${esc(ui.wallet)}</strong></label><label>申请时间<strong>${time(w.created_at)}</strong></label><label>交易哈希<strong>${w.tx_hash||'尚未生成'}</strong></label><label>交易状态<strong>${done?'成功':pending?'等待财务审批':w.status}</strong></label><label>命中策略<strong>财务审批 · 单笔限额 · 单日限额 · 网络手续费储备${verificationEnabled?' · External validation':''}</strong></label><label>手续费安全线<strong>${reserve?`${amount(reserve.minimum_required)} ${esc(reserve.native_asset)} minimum · ${amount(reserve.estimated_per_transaction)} per transaction`:'未配置'}</strong></label><label>External validation<strong>${validation?esc(validation.detail):verificationEnabled?'Required before signing':'Disabled'}</strong></label><label>申请备注<strong>${esc(w.user_id||'暂无备注')}</strong></label></div><div class="approval-progress"><h3>审批进度</h3><p><i></i><b>${esc(w.merchant)}</b><span>发起　${time(w.created_at)}</span></p><p><i></i><b>M2 Risk Engine</b><span>${reserveReady?'Network fee reserve check passed':'Network fee reserve check blocked'}</span></p>${validation?`<p><i></i><b>Merchant platform</b><span>${esc(validation.detail)}</span></p>`:''}${!pending?`<p><i></i><b>${esc(currentUser.display_name)}</b><span>审批通过</span></p>`:''}${done?`<p><i></i><b>M2 签名服务</b><span>签名通过</span></p>`:''}</div>${pending&&roleCan('ADMIN','FINANCE')?`<div class="workflow-actions"><button class="btn" data-action="reject-withdrawal" data-withdrawal-id="${w.id}">拒绝</button><button class="btn primary" data-action="approve-withdrawal" data-withdrawal-id="${w.id}" ${reserveReady?'':'disabled'}>${reserveReady?'审批通过':'手续费储备不足'}</button></div>`:''}</aside>`;}

function waasPage(){
  if(ui.page==='waas-settings')return settingsPage();
  if(ui.page==='waas-error'){const rows=data.callbacks.filter(x=>x.status==='FAILED');return waasCallbackList('异常回调',rows,true);}
  if(ui.page==='waas-history')return waasCallbackList('历史回调',data.callbacks,false);
  return `<section class="page waas-page"><div class="toolbar"><h1>钱包提币</h1><div class="toolbar-actions"><button class="btn">▽</button><button class="btn">排序⌄</button></div></div>${data.withdrawals.length?`<div class="waas-native-list">${data.withdrawals.map(w=>`<div class="waas-native-row" data-waas-item="withdrawal:${w.id}">${coinMark(w.currency)}<span><b>${w.currency}-${w.network==='TRON'?'TRC20':w.network} ${status(w.status)}</b><small>${short(w.to_address,16,10)}</small></span><strong>${amount(w.amount)} ${w.currency}-${w.network==='TRON'?'TRC20':w.network}<small>${time(w.created_at)}</small></strong></div>`).join('')}</div>`:empty()}${ui.waasItem?waasDetailDrawer(ui.waasItem):''}</section>`;
}
function callbackStatus(c){if(c.status==='PENDING'&&!c.callback_url)return '<span class="status pending">未配置</span>';if(c.status==='PENDING')return '<span class="status pending">待推送</span>';return status(c.status);}
function callbackBusiness(c){return String(c.event_type||'').startsWith('payment.')?'支付订单':'钱包提币';}
function waasCallbackList(title,rows,error){const receipts=data.webhookReceipts||[];return `<section class="page waas-page"><div class="toolbar"><h1>${title}</h1><div class="toolbar-actions"><button class="btn">▽</button>${!error&&roleCan('ADMIN','OPERATOR')?'<button class="btn primary" data-action="deliver-callbacks">Deliver pending callbacks</button>':''}</div></div>${!error?`<div class="callback-sandbox"><span>Merchant integration sandbox</span><strong>${receipts.length} verified request${receipts.length===1?'':'s'}</strong><small>Signed callbacks and pre-payout validations are verified and persisted locally.</small></div>`:''}${rows.length?`<div class="waas-native-list">${rows.map(c=>`<div class="waas-native-row callback-row" data-waas-item="callback:${c.id}"><span class="callback-icon">↻</span><span><b>${callbackBusiness(c)}</b><small>业务编号：${short(c.reference_id,14,8)}</small><small>回调 URL：${c.callback_url?esc(c.callback_url):'未配置 URL'}</small></span><strong>${callbackStatus(c)}<small>${time(c.updated_at||c.created_at)}</small>${error?`<span class="row-actions"><button class="btn">忽略</button><button class="btn primary" data-retry="${c.id}">推单</button></span>`:''}</strong></div>`).join('')}</div>`:empty(title==='异常回调'?'暂无异常回调':'暂无数据')}${ui.waasItem?waasDetailDrawer(ui.waasItem):''}</section>`;}
function waasDetailDrawer(key){const [type,id]=key.split(':');if(type==='withdrawal'){const w=data.withdrawals.find(x=>x.id===id);if(!w)return'';return `<aside class="waas-detail"><div class="waas-detail-head"><h2>详情</h2><button data-action="close-waas-detail">×</button></div><div class="waas-amount"><span>${status(w.status)}</span><h2>${amount(w.amount)} ${w.currency}-${w.network==='TRON'?'TRC20':w.network}</h2></div><div class="tx-fields"><label>钱包<strong>${esc(w.merchant)} · M2 主钱包</strong></label><label>发送方<strong>M2-DEMO-SENDER-ADDRESS</strong></label><label>接收方<strong>${esc(w.to_address)}</strong></label><label>三方业务编号<strong>${esc(w.merchant_withdraw_id)}</strong></label><label>发起时间<strong>${time(w.created_at)}</strong></label><label>完成时间<strong>${w.status==='CONFIRMED'?time(w.updated_at):'—'}</strong></label><label>回调地址<strong>${w.callback_url||'未配置'}</strong></label><label>IP地址<strong>127.0.0.1（Demo）</strong></label><label>交易哈希<strong>${w.tx_hash||'尚未生成'}</strong></label><label>备注<strong>${esc(w.user_id||'暂无备注')}</strong></label></div></aside>`;}const c=data.callbacks.find(x=>x.id===id);if(!c)return'';const w=data.withdrawals.find(x=>x.id===c.reference_id),p=data.payments.find(x=>x.id===c.reference_id),business=callbackBusiness(c),target=w?.to_address||p?.pay_address||c.reference_id,txHash=w?.tx_hash||p?.tx_hash;return `<aside class="waas-detail"><div class="waas-detail-head"><h2>详情</h2><button data-action="close-waas-detail">×</button></div><div class="waas-amount"><small>${business}</small><h2>${w?`${amount(w.amount)} ${w.currency}-${w.network==='TRON'?'TRC20':w.network}`:p?`${amount(p.amount)} ${p.pay_currency}-${p.network}`:esc(c.event_type)}</h2></div><div class="tx-fields"><label>业务类型<strong>${business}</strong></label><label>项目<strong>${business==='支付订单'?'M2 收付项目':'M2 Pay Internal'}</strong></label><label>${business==='支付订单'?'支付地址':'接收方'}<strong>${esc(target)}</strong></label><label>回调状态<strong>${callbackStatus(c)}</strong></label><label>三方业务编号<strong>${esc(c.reference_id)}</strong></label><label>更新时间<strong>${time(c.updated_at||c.created_at)}</strong></label><label>回调地址<strong>${c.callback_url||'未配置'}</strong></label><label>交易哈希<strong>${txHash||'尚未生成'}</strong></label><label>失败原因<strong>${c.last_error||(!c.callback_url?'未配置回调地址':'—')}</strong></label></div></aside>`;}
function settingsPage(){const tab=ui.settingTab;return `<section class="page"><div class="toolbar"><h1>设置</h1></div><div class="settings-layout"><div class="setting-tabs">${[['developer','开发者'],['console','API Console'],['ip','IP白名单'],['callback','回调设置'],['notice','通知设置']].map(([id,label])=>`<button class="${tab===id?'active':''}" data-setting="${id}">${label}</button>`).join('')}</div><div class="setting-panel">${settingContentV2(tab)}</div></div></section>`;}
function settingContent(tab){if(tab==='ip')return `<h3>M2 Wallet API 只允许白名单中的 IP 地址访问</h3><button class="btn primary">创建组</button>${empty('暂未创建 IP 组')}`;if(tab==='callback')return `<h3>回调设置</h3><div class="setting-row"><div><strong>批量修改回调地址</strong><small>统一设置项目的业务回调 URL</small></div><button class="btn">编辑</button></div><div class="setting-row"><div><strong>提币外部验证</strong><small>出款前调用客户平台进行最终校验</small></div><span class="switch on"></span></div><div class="setting-row"><div><strong>最小回调金额</strong><small>阻止粉尘交易和小额骚扰回调</small></div><button class="btn">配置</button></div>`;if(tab==='notice')return `<h3>通知设置</h3>${[['异常回调','系统自动回调失败时'],['启用/禁用项目','项目状态变化时'],['重置 API Key','项目 API Key 重置时']].map(x=>`<div class="setting-row"><div><strong>${x[0]}</strong><small>${x[1]}</small></div><span class="switch on"></span></div>`).join('')}`;return `<h3>项目信息</h3><div class="setting-row"><div><strong>项目名称</strong><small>M2 Pay Internal</small></div><span>启用</span></div><div class="setting-row"><div><strong>项目 ID</strong><small>PRJ-M2-DEMO-001</small></div><button class="btn">复制</button></div><div class="setting-row"><div><strong>API Key</strong><small>****************************</small></div><button class="btn">查看</button></div><div class="setting-row"><div><strong>Base URL</strong><small>http://127.0.0.1:8787/api/v1</small></div><button class="btn">API 文档</button></div>`;}
function settingContentV2(tab){
  if(tab==='console')return integrationConsoleContent();
  if(tab==='ip'){const rows=data.ipAllowlist||[];return `<h3>M2 Wallet API 只允许白名单中的 IP 地址访问</h3><div class="ip-group"><div class="ip-group-head"><b>内部服务 IP 地址</b>${roleCan('ADMIN')?'<button class="btn primary" data-action="add-ip-allowlist">添加 IP</button>':''}</div>${rows.map(x=>`<p><strong>${esc(x.name)}</strong> · ${esc(x.cidr)} <small>${esc(x.created_by)}</small></p>`).join('')||'<p>尚未配置 IP，API Key 请求暂不限制来源。</p>'}</div>`;}
  if(tab==='callback'){const s=data.projectSettings||{},mins=s.minimum_callbacks||{};return `<h3>回调设置</h3><div class="setting-row"><div><strong>业务回调地址</strong><small>${esc(s.callback_url||'未配置回调地址')}</small></div>${roleCan('ADMIN')?'<span><button class="btn" data-action="use-demo-callback">Use demo receiver</button> <button class="btn" data-action="edit-project-callback">编辑</button></span>':''}</div><div class="setting-row"><div><strong>提币外部验证</strong><small>出款前调用客户平台进行最终校验</small></div><button class="switch ${s.withdrawal_verification_enabled?'on':''}" data-action="toggle-withdrawal-verification"></button></div><h3 class="settings-subtitle">最小回调金额设置</h3><p class="settings-note">低于阈值的支付仍然入账，但回调事件会标记为忽略。</p><div class="api-type-row"><strong>USDT</strong><p>${amount(mins.USDT)} USDT</p><button class="btn" data-action="edit-minimum-callback" data-callback-asset="USDT">编辑</button></div><div class="api-type-row"><strong>USDC</strong><p>${amount(mins.USDC)} USDC</p><button class="btn" data-action="edit-minimum-callback" data-callback-asset="USDC">编辑</button></div>`;}
  if(tab==='notice')return `<h3>通知设置</h3>${[['异常回调','系统自动回调失败时'],['启用/禁用项目','项目启用/禁用时'],['重置 API Key','重置项目 API Key 时']].map(x=>`<div class="setting-row"><div><strong>${x[0]}</strong><small>${x[1]}</small></div><span class="switch on"></span></div>`).join('')}`;
  const s=data.projectSettings||{};return `<h3>项目信息</h3><div class="settings-field"><small>项目名称</small><strong>M2 Pay Internal</strong></div><div class="settings-field"><small>创建时间</small><strong>2026-07-22 10:00:00</strong></div><div class="settings-field"><small>创建人</small><strong>M2 System Admin</strong></div><div class="setting-row"><div><small>项目状态</small><strong>${s.enabled?'启用':'禁用'}</strong></div>${roleCan('ADMIN')?`<button class="switch ${s.enabled?'on':''}" data-action="toggle-project"></button>`:`<span class="switch ${s.enabled?'on':''}"></span>`}</div><h3 class="settings-divider">开发者中心</h3><div class="settings-field"><small>项目 ID</small><strong>PRJ-M2-DEMO-001</strong></div><div class="setting-row"><div><small>API Key</small><strong>****************************</strong></div><span><button class="btn">查看</button> <button class="btn primary">重置</button></span></div><div class="settings-field"><small>Base URL</small><strong>http://127.0.0.1:8787/api/v1</strong></div><p class="dev-links">API 文档　›　　SDK 下载　›</p><h3 class="settings-divider">接口类型</h3><div class="api-type-row"><strong>生成子地址</strong><p>帮助业务平台实现订单多资产支付，满足平台多样化的运营方式</p><span>钱包　--</span></div><div class="api-type-row"><strong>提币</strong><button class="btn">编辑</button><p>协助平台实现加密资产提现，并在 M2 Wallet 完成审批与签名放款</p><span>策略　财务审批　　出款钱包　M2 主钱包　　★ 默认出款</span></div>`;
}

function integrationConsoleContent(){const latestPayment=data.payments[0],latestWithdrawal=data.withdrawals[0],last=ui.integrationResponse;const samples=[
  {id:'create-usdt-payment',method:'POST',path:'/payment-orders',title:'Create USDT payment',desc:'Generate a TRON payment address and checkout order.'},
  {id:'create-usdc-payment',method:'POST',path:'/payment-orders',title:'Create USDC payment',desc:'Generate a Polygon payment address and checkout order.'},
  {id:'create-usdt-withdrawal',method:'POST',path:'/withdrawals',title:'Submit USDT withdrawal',desc:'Send a merchant withdrawal into finance approval.'},
  {id:'create-usdc-withdrawal',method:'POST',path:'/withdrawals',title:'Submit USDC withdrawal',desc:'Send a Polygon payout into finance approval.'},
  {id:'query-payment',method:'GET',path:`/payment-orders/${latestPayment?.merchant_order_id||'{merchant_order_id}'}`,title:'Query payment status',desc:'Look up an order using the merchant reference.'},
  {id:'query-withdrawal-events',method:'GET',path:`/withdrawals/${latestWithdrawal?.merchant_withdraw_id||'{merchant_withdraw_id}'}/events`,title:'Query payout timeline',desc:'Inspect approval, signing, broadcast, and confirmation events.'}
];const shareable=!['127.0.0.1','localhost'].includes(location.hostname);return `<div class="integration-console"><div class="console-intro"><div><small>MERCHANT INTEGRATION SANDBOX</small><h2>API Console</h2><p>Run safe sample requests against the current M2 Wallet environment. No real assets are used.</p></div><span class="status pending">${shareable?'Shareable sandbox':'Local API'}</span></div><div class="console-base"><span>Base URL</span><code>${location.origin}/api/v1</code><button class="btn" data-copy="${location.origin}/api/v1">Copy</button></div><div class="console-samples">${samples.map(s=>`<button class="console-sample" data-action="run-api-sample" data-sample="${s.id}"><span class="http-method ${s.method.toLowerCase()}">${s.method}</span><div><b>${s.title}</b><code>${s.path}</code><small>${s.desc}</small></div><i>Run ›</i></button>`).join('')}</div>${last?`<div class="console-result"><div class="console-result-head"><div><span class="http-method ${last.method.toLowerCase()}">${last.method}</span><code>${esc(last.path)}</code></div><strong class="${last.ok?'ok':'bad'}">${last.status} ${last.ok?'Success':'Error'}</strong></div>${last.request?`<label>Request body</label><pre>${esc(JSON.stringify(last.request,null,2))}</pre>`:''}<label>Response</label><pre>${esc(JSON.stringify(last.response,null,2))}</pre>${last.next?`<button class="btn primary" data-action="open-finance-approval" data-withdrawal-id="${last.next.id}">${last.next.label}</button>`:''}</div>`:'<div class="console-placeholder">Choose a request above to see its request and response payload.</div>'}</div>`;}

function paymentPage(){if(ui.page==='payment-orders')return paymentOrders();return `<section class="hero"><div><h1>M2 Wallet 加密支付引擎</h1><h2>帮助支付业务拓展全球市场</h2><ul><li><strong>全球支付</strong><small>支持稳定币、多种主流加密货币及链</small></li><li><strong>高效的稳定币结算</strong><small>提升资金流动性，轻松应对业务需求</small></li><li><strong>支付风控</strong><small>监控交易与回调状态，保障业务资金安全</small></li><li><strong>简单的接入流程</strong><small>低代码收银台与支付 API 让业务快速启动</small></li></ul><button class="btn primary" data-page="payment-orders">进入支付项目</button> <button class="btn">查看 API 文档</button></div><div class="hero-art"><div></div></div></section>`;}
function paymentOrders(){return `<section class="page"><div class="toolbar"><h1>支付订单</h1><button class="btn primary" data-action="create-payment">创建订单</button></div><div class="filter-bar"><input placeholder="商户订单号"/><select><option>全部状态</option><option>待支付</option><option>已完成</option></select></div><table class="data-table"><thead><tr><th>创建时间</th><th>商户订单号</th><th>客户平台</th><th>支付币种/网络</th><th>金额</th><th>平台佣金</th><th>状态</th><th>支付地址</th></tr></thead><tbody>${data.payments.map(p=>`<tr><td>${time(p.created_at)}</td><td><span class="cell-main">${esc(p.merchant_order_id)}</span><span class="cell-sub">${p.id}</span></td><td>${esc(p.merchant)}</td><td>${p.pay_currency}<span class="cell-sub">${p.network}</span></td><td>${amount(p.amount)} ${p.order_currency}</td><td>${amount(p.fee_amount)}</td><td>${status(p.status)}</td><td>${short(p.pay_address,8,6)}</td></tr>`).join('')}</tbody></table>${data.payments.length?'':empty()}</section>`;}
function paymentPageV2(){if(ui.page==='landing')return paymentPage();if(ui.page==='payment-settlements')return paymentSettlementsPage();if(ui.page==='payment-settings')return paymentSettingsPage();return paymentOrdersV2();}
function paymentOrdersV2(){return `<section class="page payment-project-page"><div class="toolbar"><h1>支付订单</h1><button class="btn primary" data-action="create-payment">创建订单</button></div><div class="payment-filter"><input placeholder="订单号、交易哈希"/><button class="btn">状态⌄</button><input type="date"/><span>–</span><input type="date"/><button class="btn">导出</button></div><table class="data-table payment-table"><thead><tr><th>订单号 | 创建时间</th><th>订单金额 | 支付币种</th><th>实付金额 | 平台手续费</th><th>状态</th></tr></thead><tbody>${data.payments.map(p=>`<tr data-payment-item="${p.id}"><td><span class="cell-main">${esc(p.merchant_order_id)}</span><span class="cell-sub">${time(p.created_at)}</span></td><td>${amount(p.amount)} ${p.order_currency}<span class="cell-sub">${p.pay_currency}-${p.network}</span></td><td>${amount(p.paid_amount)} ${p.pay_currency}<span class="cell-sub">${amount(p.fee_amount)} ${p.pay_currency}</span></td><td>${status(p.status)}</td></tr>`).join('')}</tbody></table>${data.payments.length?'':empty('暂无支付订单')}${ui.paymentItem?paymentOrderDrawer(data.payments.find(p=>p.id===ui.paymentItem)):''}</section>`;}
function paymentSimulationActions(p){if(!roleCan('ADMIN','OPERATOR')||!['PENDING','PARTIAL'].includes(p.status))return'';const expected=Number(p.amount||0),paid=Number(p.paid_amount||0),remaining=Math.max(expected-paid,0),under=Math.max(expected*.5-paid,expected*.1),over=Math.max(expected*1.05-paid,expected*.05);return `<div class="payment-simulation"><small>Demo scenarios</small><button class="btn" data-simulate-payment="${p.id}" data-paid-amount="${under.toFixed(6)}">Simulate underpayment</button><button class="btn primary" data-simulate-payment="${p.id}" data-paid-amount="${remaining.toFixed(6)}">Simulate full payment</button><button class="btn" data-simulate-payment="${p.id}" data-paid-amount="${over.toFixed(6)}">Simulate overpayment</button><button class="btn danger" data-expire-payment="${p.id}">Mark expired</button></div>`;}
function paymentOrderDrawer(p){if(!p)return'';return `<aside class="waas-detail payment-detail"><div class="waas-detail-head"><h2>支付订单详情</h2><button data-action="close-payment-detail">×</button></div><div class="waas-amount"><span>${status(p.status)}</span><h2>${amount(p.amount)} ${p.order_currency}</h2></div><div class="tx-fields"><label>订单号<strong>${esc(p.merchant_order_id)}</strong></label><label>M2 订单 ID<strong>${esc(p.id)}</strong></label><label>客户平台<strong>${esc(p.merchant)}</strong></label><label>Customer ID<strong>${esc(p.customer_id||'—')}</strong></label><label>支付币种<strong>${p.pay_currency}-${p.network}</strong></label><label>支付地址<strong>${esc(p.pay_address)}</strong></label><label>订单金额<strong>${amount(p.amount)} ${p.order_currency}</strong></label><label>实付金额<strong>${amount(p.paid_amount)} ${p.pay_currency}</strong></label><label>平台手续费<strong>${amount(p.fee_amount)} ${p.pay_currency}</strong></label><label>到期时间<strong>${time(p.expires_at)}</strong></label><label>Return URL<strong>${esc(p.return_url||'—')}</strong></label><label>完成时间<strong>${['CONFIRMED','OVERPAID'].includes(p.status)?time(p.updated_at):'—'}</strong></label><label>交易哈希<strong>${p.tx_hash||'尚未生成'}</strong></label></div><div class="payment-actions"><button class="btn" data-copy="${esc(p.pay_address)}">复制支付地址</button><button class="btn" data-preview-checkout="${p.id}">预览客户收银台</button><a class="btn" href="/pay/${encodeURIComponent(p.id)}" target="_blank" rel="noopener">打开独立收银台</a></div>${paymentSimulationActions(p)}</aside>`;}
function paymentCheckoutDialog(id){const p=data.payments.find(x=>x.id===id);if(!p)return;const cells=Array.from({length:81},(_,i)=>`<i class="${((i*17+id.charCodeAt(i%id.length))%5)<2?'on':''}"></i>`).join('');openDialog(`<div class="checkout-preview"><div class="dialog-head"><div><small>M2 Wallet Pay</small><h2>${esc(p.merchant)}</h2></div><button class="dialog-close" data-action="close-dialog">×</button></div><div class="checkout-status">${status(p.status)}</div><p>请支付</p><h1>${amount(p.amount)} ${p.pay_currency}</h1><span class="checkout-network">${p.network} 网络</span><div class="checkout-qr" aria-label="Demo 收款二维码">${cells}</div><small>Demo 收款码 · 正式版本将生成可扫码链上 URI</small><div class="checkout-address"><span>${esc(p.pay_address)}</span><button class="btn" data-copy="${esc(p.pay_address)}">复制</button></div><div class="checkout-note">仅向此地址支付 ${p.pay_currency}，并确认使用 ${p.network} 网络。订单号：${esc(p.merchant_order_id)}</div>${p.status==='PENDING'&&roleCan('ADMIN','OPERATOR')?`<button class="btn primary checkout-paid" data-simulate-payment="${p.id}">模拟客户已完成付款</button>`:''}</div>`);}
function settlementGroups(){const groups={};for(const p of data.payments.filter(x=>x.status==='CONFIRMED')){const key=`${p.pay_currency}-${p.network}`;if(!groups[key])groups[key]={key,currency:p.pay_currency,network:p.network,total:0,fee:0,orders:[],updated_at:p.updated_at};const g=groups[key];g.total+=Number(p.amount||0);g.fee+=Number(p.fee_amount||0);g.orders.push(p);if(String(p.updated_at)>String(g.updated_at))g.updated_at=p.updated_at;}return Object.values(groups);}
function paymentSettlementsPage(){const groups=settlementGroups(),count=groups.reduce((s,g)=>s+g.orders.length,0),day=new Date().toISOString().slice(0,10).replaceAll('-','');return `<section class="page"><div class="toolbar"><h1>结算记录</h1><button class="btn">导出流水</button></div><div class="payment-filter"><input placeholder="结算单号"/><button class="btn">状态⌄</button><input type="date"/><span>–</span><input type="date"/></div><table class="data-table"><thead><tr><th>结算单号 | 结算时间</th><th>交易总金额 | 支付笔数</th><th>结算总金额 | 总手续费</th></tr></thead><tbody>${groups.map(g=>`<tr data-settlement-item="${g.key}"><td><span class="cell-main">SETTLE-${g.currency}-${day}</span><span class="cell-sub">${time(g.updated_at)}</span></td><td>${amount(g.total)} ${g.currency}<span class="cell-sub">${g.orders.length} 笔 · ${g.network}</span></td><td>${amount(g.total-g.fee)} ${g.currency}<span class="cell-sub">${amount(g.fee)} ${g.currency}</span></td></tr>`).join('')}</tbody></table>${groups.length?'':empty('暂无结算记录')}<div class="settlement-total">结算总笔数 ${count}　|　${groups.map(g=>`${g.currency} 净结算 ${amount(g.total-g.fee)}`).join('　·　')}</div>${ui.settlementItem?settlementDrawer(groups.find(g=>g.key===ui.settlementItem),day):''}</section>`;}
function settlementDrawer(g,day){if(!g)return'';return `<aside class="waas-detail payment-detail"><div class="waas-detail-head"><h2>结算详情</h2><button data-action="close-payment-settlement">×</button></div><div class="waas-amount"><span>${status('CONFIRMED')}</span><h2>${amount(g.total-g.fee)} ${g.currency}</h2></div><div class="tx-fields"><label>结算单号<strong>SETTLE-${g.currency}-${day}</strong></label><label>支付网络<strong>${g.network}</strong></label><label>支付笔数<strong>${g.orders.length} 笔</strong></label><label>交易总金额<strong>${amount(g.total)} ${g.currency}</strong></label><label>平台手续费<strong>${amount(g.fee)} ${g.currency}</strong></label><label>净结算金额<strong>${amount(g.total-g.fee)} ${g.currency}</strong></label><label>结算钱包<strong>M2 主钱包</strong></label><label>结算时间<strong>${time(g.updated_at)}</strong></label></div><div class="settlement-orders"><h3>包含订单</h3>${g.orders.map(p=>`<p><strong>${esc(p.merchant_order_id)}</strong><span>${amount(p.amount)} ${g.currency}</span></p>`).join('')}</div></aside>`;}
function paymentSettingsPage(){const tab=ui.paymentSettingTab;const tabs=[['developer','开发者'],['ip','IP白名单'],['notice','通知设置'],['coins','支付币种与结算'],['merchant','商户信息'],['order','订单处理']];return `<section class="page"><div class="toolbar"><h1>设置</h1></div><div class="payment-settings-tabs">${tabs.map(([id,label])=>`<button class="${tab===id?'active':''}" data-payment-setting="${id}">${label}</button>`).join('')}</div><div class="payment-settings-body">${paymentSettingContent(tab)}</div></section>`;}
function paymentSettingContent(tab){if(tab==='coins')return `<h3>支付币种与结算</h3><div class="api-type-row"><strong>USDT</strong><p>TRON · 订单支付币种</p><span>结算币种 USDT　结算钱包 M2 主钱包　自动结算</span></div><div class="api-type-row"><strong>USDC</strong><p>Polygon · 订单支付币种</p><span>结算币种 USDC　结算钱包 M2 主钱包　自动结算</span></div><button class="btn primary">添加支付币种</button>`;if(tab==='merchant')return `<h3>商户信息</h3><div class="settings-field"><small>商户名称</small><strong>M2 Internal Merchant</strong></div><div class="settings-field"><small>联系邮箱</small><strong>internal@m2wallet.demo</strong></div><div class="settings-field"><small>收银台品牌</small><strong>M2 Wallet Pay</strong></div><button class="btn">编辑</button>`;if(tab==='order')return `<h3>订单处理</h3><div class="setting-row"><div><strong>USDT</strong><small>订单币种 · 超付容差 1% · 少付容差 1%</small></div><button class="btn">编辑</button></div><div class="setting-row"><div><strong>订单有效期</strong><small>创建后 30 分钟</small></div><button class="btn">编辑</button></div><div class="setting-row"><div><strong>重复支付处理</strong><small>生成异常订单并通知运营</small></div><span class="switch on"></span></div>`;if(tab==='notice')return settingContentV2('notice');if(tab==='ip')return settingContentV2('ip');return `<h3>项目信息</h3><div class="settings-field"><small>项目名称</small><strong>M2 收付项目</strong></div><div class="setting-row"><div><small>项目状态</small><strong>启用</strong></div><span class="switch on"></span></div><h3 class="settings-divider">开发者中心</h3><div class="settings-field"><small>项目 ID</small><strong>PAY-M2-DEMO-001</strong></div><div class="setting-row"><div><small>API Key</small><strong>****************************</strong></div><span><button class="btn">查看</button> <button class="btn primary">重置</button></span></div><div class="settings-field"><small>Base URL</small><strong>http://127.0.0.1:8787/api/v1</strong></div><p class="dev-links">API 文档　›　　SDK 下载　›</p>`;}

function transactionsPage(){return `<section class="page"><div class="toolbar"><h1>交易记录</h1><div class="toolbar-actions"><button class="btn">▽ 筛选</button><button class="btn">导出</button></div></div><table class="data-table"><thead><tr><th>交易时间 UTC+08:00</th><th>币种 / 地址</th><th>交易哈希</th><th>所属钱包</th><th>交易类型</th><th>收支类型</th><th>金额</th><th>状态</th></tr></thead><tbody>${data.transactions.map(t=>{const internal=t.direction==='INTERNAL';return `<tr data-transaction-item="${t.reference_id}"><td>${time(t.updated_at)}</td><td><span class="cell-main">${t.asset} · ${t.network}</span><span class="cell-sub">${short(t.address||'',8,5)}</span></td><td>${short(t.tx_hash||'',8,5)}</td><td>M2 主钱包</td><td>${internal?'自动归集':t.direction==='OUT'?'API申请转出':'普通转入'}</td><td>${internal?'内部划转':t.direction==='OUT'?'转出':'转入'}</td><td><span class="cell-main">${amount(t.amount)} ${t.asset}</span></td><td>${status(t.status)}</td></tr>`}).join('')}</tbody></table>${data.transactions.length?'':empty()}${ui.transactionItem?globalTransactionDrawer(data.transactions.find(t=>t.reference_id===ui.transactionItem)):''}</section>`;}
function globalTransactionDrawer(t){if(!t)return'';const incoming=t.direction==='IN',internal=t.direction==='INTERNAL',sign=internal?'⇄':incoming?'+':'-';return `<aside class="waas-detail transaction-detail"><div class="waas-detail-head"><h2>交易详情</h2><button data-action="close-global-transaction">×</button></div><div class="waas-amount"><span>${status(t.status)}</span><h2>${sign} ${amount(t.amount)} ${t.asset}</h2></div><div class="tx-fields"><label>业务编号<strong>${esc(t.reference_id)}</strong></label><label>业务类型<strong>${internal?'支付地址自动归集':incoming?'稳定币收款':'API 提币 / 钱包发送'}</strong></label><label>客户平台 / 钱包<strong>${esc(t.merchant||'M2 主钱包')}</strong></label><label>网络<strong>${esc(t.network)}</strong></label><label>${internal?'归集目标地址':incoming?'收款地址':'接收方'}<strong>${esc(t.address||'—')}</strong></label><label>交易方向<strong>${internal?'子地址 → M2 主钱包':incoming?'转入':'转出'}</strong></label><label>交易时间<strong>${time(t.updated_at)}</strong></label><label>交易哈希<strong>${t.tx_hash||'尚未生成'}</strong></label></div></aside>`;}

function riskPage(){const p=ui.page||'strategy';if(p==='aml')return `<section class="hero"><div><h1>AML</h1><h2>手动/自动识别风险，增强管理能力</h2><ul><li><strong>风险评估</strong><small>发现可疑地址，提高预警能力</small></li><li><strong>交易监控</strong><small>追踪资金来源，识别可疑交易</small></li><li><strong>风险管理</strong><small>及时控制风险，保护资产安全</small></li></ul><button class="btn primary">开始查询</button></div><div class="hero-art"><div></div></div></section>`;if(['whitelist','blacklist'].includes(p))return addressBook(p);if(p==='risk-log')return `<section class="page"><div class="toolbar"><h1>日志</h1><button class="btn">筛选</button></div><div class="tabs"><button class="tab active">策略</button><button class="tab">自动化</button><button class="tab">AML</button><button class="tab">团队API</button></div>${empty('暂无风控日志')}</section>`;if(p==='automation')return `<section class="page"><div class="toolbar"><h1>自动化</h1><button class="btn primary">新增自动化</button></div><div class="card-grid"><div class="card"><h3>自动归集</h3><p>达到阈值后将子地址资产归集至指定钱包。</p><strong class="metric">启用</strong></div><div class="card"><h3>低余额补充</h3><p>自动补充 TRX 能量或链上 Gas。</p><strong class="metric">监控中</strong></div></div></section>`;return `<section class="page"><div class="toolbar"><h1>策略</h1><button class="btn primary">新增策略</button></div><div class="card-grid">${[['单笔出款限额','10,000 USDT'],['地址白名单校验','已启用'],['财务审批','必须'],['连续失败暂停','3 次']].map(x=>`<div class="card"><h3>${x[0]}</h3><p>应用于 M2 主钱包与 WaaS 提币。</p><strong class="metric">${x[1]}</strong></div>`).join('')}</div></section>`;}
function addressBook(p){const type=p==='whitelist'?'ALLOWLIST':'BLOCKLIST',rows=(data.addressBook||[]).filter(x=>x.list_type===type);return `<section class="page"><div class="toolbar"><h1>${p==='whitelist'?'白名单':'黑名单'}</h1><div><button class="btn">筛选</button> ${roleCan('ADMIN')?`<button class="btn primary" data-action="add-address-book" data-list-type="${type}">新增</button>`:''}</div></div><table class="data-table"><thead><tr><th>币种</th><th>网络</th><th>别名</th><th>地址</th><th>创建时间</th><th>创建人</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${esc(x.asset)}</td><td>${esc(x.network)}</td><td>${esc(x.alias)}</td><td><code>${esc(x.address)}</code></td><td>${time(x.created_at)}</td><td>${esc(x.created_by)}</td></tr>`).join('')}</tbody></table>${rows.length?'':empty('暂无地址')}</section>`;}

function managementPage(){const p=ui.page||'subscription';if(p==='members')return teamTable('成员',[['成员','角色','状态','加入时间'],['财务演示账户','财务审批','正常','2026-07-22'],['运营演示账户','运营人员','正常','2026-07-22'],['只读演示账户','普通成员','正常','2026-07-22']]);if(p==='roles')return `<section class="page"><div class="toolbar"><h1>角色</h1><button class="btn primary">新增</button></div><div class="card-grid">${['超级管理员','管理员','普通成员','云端审核'].map((x,i)=>`<div class="card"><h3>${x}</h3><p>${i===0?'拥有全部团队、钱包和审批权限':'按模块分配查看与操作权限'}</p><strong class="metric">${[1,2,1,1][i]} 人</strong></div>`).join('')}</div></section>`;if(p==='security')return `<section class="page"><div class="toolbar"><h1>团队安全</h1><button class="btn">更多</button></div>${[['企业认证','完成团队认证后开放更多服务','未认证'],['白名单校验','开启后禁止向非白名单地址转账','已开启'],['风控策略','策略引擎实时保护资产安全','查看'],['邀请成员','邀请成员加入内部团队','邀请']].map(x=>`<div class="setting-row"><div><strong>${x[0]}</strong><small>${x[1]}</small></div><button class="btn">${x[2]}</button></div>`).join('')}</section>`;if(p==='team-api')return apiKeysPage();if(p==='account')return `<section class="page"><div class="toolbar"><h1>团队账户</h1><button class="btn primary">充值</button></div><div class="card"><h3>团队账户</h3><strong class="metric">$ 1,000.00</strong><p>用于平台服务、AML 查询和链上资源消耗。</p></div><div class="tabs"><button class="tab active">明细</button></div>${empty('暂无消费明细')}</section>`;if(p==='orders')return teamTable('订单管理',[['订单号','服务','金额','状态','创建时间'],['ORDER-DEMO-001','内部试用版','$ 0','已完成','2026-07-22']]);return `<section class="page"><div class="toolbar"><h1>内部试用版</h1><button class="btn primary">升级</button></div><div class="card-grid"><div class="card"><h3>钱包地址数</h3><strong class="metric">5 / 2,000</strong><p>单签、多签和 WaaS 子地址</p></div><div class="card"><h3>API 交易笔数</h3><strong class="metric">${data.transactions.length} / 100,000</strong><p>本月使用量</p></div><div class="card"><h3>团队成员</h3><strong class="metric">4 / 20</strong><p>成员和角色权限</p></div><div class="card"><h3>风控策略</h3><strong class="metric">4 / 10</strong><p>策略与自动化</p></div><div class="card"><h3>高级功能</h3><strong class="metric">已开通</strong><p>自动归集 / 独立签名</p></div></div></section>`;}
function apiKeysPage(){const rows=data.apiKeys||[];return `<section class="page api-keys-page"><div class="toolbar"><div><h1>Team API</h1><small>Hashed credentials with least-privilege access scopes</small></div><button class="btn primary" data-action="create-api-key">Create API key</button></div><div class="api-key-summary"><div><span>Active keys</span><strong>${rows.filter(x=>x.status==='ACTIVE').length}</strong></div><div><span>Storage</span><strong>SHA-256 hash only</strong></div><div><span>Source control</span><strong>IP allowlist protected</strong></div></div><table class="data-table"><thead><tr><th>Name / Key prefix</th><th>Permissions</th><th>Created by</th><th>Last used</th><th>Status</th><th>Actions</th></tr></thead><tbody>${rows.map(k=>`<tr><td><span class="cell-main">${esc(k.name)}</span><span class="cell-sub">${esc(k.key_prefix)}•••• · ${esc(k.id)}</span></td><td><div class="scope-list">${k.scopes.map(s=>`<span>${esc(s)}</span>`).join('')}</div></td><td>${esc(k.created_by)}<span class="cell-sub">${time(k.created_at)}</span></td><td>${k.last_used_at?time(k.last_used_at):'Never'}</td><td>${status(k.status==='ACTIVE'?'CONFIRMED':'FAILED')}</td><td>${k.id==='API-ENVIRONMENT'?'<small>Managed by environment</small>':`<button class="btn" data-action="rotate-api-key" data-api-key-id="${k.id}">Rotate</button> <button class="btn ${k.status==='ACTIVE'?'danger':''}" data-action="toggle-api-key" data-api-key-id="${k.id}" data-enabled="${k.status!=='ACTIVE'}">${k.status==='ACTIVE'?'Disable':'Enable'}</button>`}</td></tr>`).join('')}</tbody></table>${rows.length?'':empty('No API keys')}</section>`;}

function demoAcceptancePage(){const r=data.readiness||{checks:[],score:0,passed:0,total:0};return `<section class="page acceptance-page"><div class="acceptance-hero"><div><span>INTERNAL DEMO READINESS</span><h1>${r.ready?'Ready for internal acceptance':'Acceptance checks in progress'}</h1><p>Live evidence from the M2 Wallet database, ledger, callbacks, approvals, and risk engine.</p></div><strong>${r.score}%<small>${r.passed} of ${r.total} checks passed</small></strong></div><div class="acceptance-grid">${(r.checks||[]).map(c=>`<div class="acceptance-card ${c.passed?'passed':'pending'}"><i>${c.passed?'✓':'!'}</i><div><b>${esc(c.label)}</b><small>${esc(c.evidence)}</small></div><span>${c.passed?'Passed':'Pending'}</span></div>`).join('')}</div><div class="acceptance-footer"><span>Environment: ${esc(r.mode||'simulation')}</span><span>Generated: ${time(r.generated_at)}</span><button class="btn" data-action="refresh-readiness">Refresh evidence</button></div></section>`;}
function teamTable(title,rows){const [heads,...body]=rows;return `<section class="page"><div class="toolbar"><h1>${title}</h1><button class="btn primary">创建</button></div><table class="data-table"><thead><tr>${heads.map(x=>`<th>${x}</th>`).join('')}</tr></thead><tbody>${body.map(r=>`<tr>${r.map(x=>`<td>${x}</td>`).join('')}</tr>`).join('')}</tbody></table></section>`;}
function marketPage(){return `<section class="page"><div class="toolbar"><h1>应用市场</h1><button class="btn">全部分类⌄</button></div><div class="card-grid">${[['链上地址分析','识别高风险地址与资金来源'],['TRON 能量服务','降低 USDT-TRC20 转账成本'],['企业通知中心','异常回调和审批消息提醒'],['财务报表','资产、佣金和对账报表']].map(x=>`<div class="card"><span class="coin">＋</span><h3 style="margin-top:18px">${x[0]}</h3><p>${x[1]}</p><button class="btn" style="margin-top:18px">查看</button></div>`).join('')}</div></section>`;}

function openDialog(html){document.getElementById('dialogBody').innerHTML=`<div class="dialog-panel">${html}</div>`;document.getElementById('actionDialog').showModal();}
function showApiKeySecret(record,title='API key created'){openDialog(`<div class="dialog-head"><div><small>ONE-TIME SECRET</small><h2>${title}</h2></div><button class="dialog-close" data-action="close-dialog">×</button></div><p class="secret-warning">Copy this key now. For security, M2 Wallet stores only its hash and cannot show the secret again.</p><div class="api-secret"><code>${esc(record.secret)}</code><button class="btn primary" data-copy="${esc(record.secret)}">Copy</button></div><div class="settings-field"><small>Key name</small><strong>${esc(record.name)}</strong></div><div class="scope-list">${record.scopes.map(s=>`<span>${esc(s)}</span>`).join('')}</div><div style="text-align:right;margin-top:22px"><button class="btn primary" data-action="close-dialog">I have saved the key</button></div>`);}
async function runApiSample(sample){const stamp=Date.now(),tron='TCGrXtAjSDfUV2xxNEgaui28odN6MdyHun',polygon='0xcee5bda9569f39eb9657472c4f8d5290f58653ad';let method='GET',path='',request=null;
  if(sample==='create-usdt-payment'){method='POST';path='/payment-orders';request={merchant_order_id:`CONSOLE-USDT-${stamp}`,merchant:'API Console Merchant',customer_id:'CUST-CONSOLE-001',amount:'25.00',order_currency:'USD',pay_currency:'USDT',network:'TRON',metadata:{source:'api-console'}};}
  if(sample==='create-usdc-payment'){method='POST';path='/payment-orders';request={merchant_order_id:`CONSOLE-USDC-${stamp}`,merchant:'API Console Merchant',customer_id:'CUST-CONSOLE-002',amount:'45.00',order_currency:'USD',pay_currency:'USDC',network:'POLYGON',metadata:{source:'api-console'}};}
  if(sample==='create-usdt-withdrawal'){method='POST';path='/withdrawals';request={merchant_withdraw_id:`CONSOLE-WD-USDT-${stamp}`,merchant:'API Console Merchant',user_id:'CUST-CONSOLE-003',amount:'12.00',currency:'USDT',network:'TRON',to_address:tron,metadata:{source:'api-console'}};}
  if(sample==='create-usdc-withdrawal'){method='POST';path='/withdrawals';request={merchant_withdraw_id:`CONSOLE-WD-USDC-${stamp}`,merchant:'API Console Merchant',user_id:'CUST-CONSOLE-004',amount:'18.00',currency:'USDC',network:'POLYGON',to_address:polygon,metadata:{source:'api-console'}};}
  if(sample==='query-payment'){const item=data.payments[0];path=`/payment-orders/${item?.merchant_order_id||'missing'}`;}
  if(sample==='query-withdrawal-events'){const item=data.withdrawals[0];path=`/withdrawals/${item?.merchant_withdraw_id||'missing'}/events`;}
  try{const response=await api(`/api/v1${path}`,{method,body:request?JSON.stringify(request):undefined});ui.integrationResponse={ok:true,status:method==='POST'?201:200,method,path,request,response,next:sample.includes('withdrawal')&&method==='POST'?{id:response.id,label:'Open finance approval'}:null};if(method==='POST')await loadData();else render();toast(`${method} ${path} completed`);}catch(error){ui.integrationResponse={ok:false,status:error.status||400,method,path,request,response:{error:{message:error.message}}};render();toast(`Request failed: ${error.message}`);}}
function sendDialog(){openDialog(`<div class="dialog-head"><h2>发送</h2><button class="dialog-close" data-action="close-dialog">×</button></div><div class="send-steps"><div class="step"><span class="step-num">1</span><div><label>选择币种</label><select><option>USDT · Tether USD</option><option>USDC · USD Coin</option></select></div></div><div class="step"><span class="step-num">2</span><div><label>选择网络</label><select><option>TRON</option><option>Polygon</option></select></div></div><div class="step"><span class="step-num">3</span><div><label>接收方地址</label><input placeholder="输入或粘贴地址"/></div></div><div class="step"><span class="step-num">4</span><div><label>输入交易金额</label><input placeholder="0.00"/></div></div><div style="text-align:right"><button class="btn" data-action="close-dialog">取消</button> <button class="btn primary" data-action="demo-send">进入财务审批</button></div></div>`);}
function createPaymentDialog(){openDialog(`<div class="dialog-head"><h2>创建稳定币支付订单</h2><button class="dialog-close" data-action="close-dialog">×</button></div><form id="paymentCreateForm" class="send-steps"><div class="step"><span class="step-num">1</span><div><label>商户订单号</label><input name="merchant_order_id" value="M${Date.now()}" required/></div></div><div class="step"><span class="step-num">2</span><div><label>客户平台</label><input name="merchant" value="Internal Merchant" required/><label>Customer ID</label><input name="customer_id" value="CUST-DEMO-001"/></div></div><div class="step"><span class="step-num">3</span><div><label>金额</label><input name="amount" value="100.00" required/></div></div><div class="step"><span class="step-num">4</span><div><label>支付币种 / 网络</label><select name="pair"><option value="USDT|TRON">USDT · TRON</option><option value="USDC|POLYGON">USDC · Polygon</option></select><label>Return URL</label><input name="return_url" placeholder="https://merchant.example/return"/></div></div><div style="text-align:right"><button type="button" class="btn" data-action="close-dialog">取消</button> <button class="btn primary">创建订单</button></div></form>`);}

document.addEventListener('click',async event=>{const el=event.target.closest('[data-action="add-ip-allowlist"],[data-action="edit-project-callback"],[data-action="use-demo-callback"],[data-action="edit-minimum-callback"],[data-action="toggle-withdrawal-verification"],[data-action="toggle-project"]');if(!el)return;try{if(el.dataset.action==='add-ip-allowlist'){const cidr=prompt('IP address or CIDR','127.0.0.1/32');if(!cidr)return;const name=prompt('IP group name','Internal service');if(name===null)return;await api('/api/v1/ip-allowlist',{method:'POST',body:JSON.stringify({cidr,name})});}else if(el.dataset.action==='edit-project-callback'){const value=prompt('HTTPS callback URL (leave empty to disable)',data.projectSettings.callback_url||'');if(value===null)return;await api('/api/v1/project-settings',{method:'POST',body:JSON.stringify({callback_url:value.trim()})});}else if(el.dataset.action==='use-demo-callback'){await api('/api/v1/project-settings',{method:'POST',body:JSON.stringify({callback_url:`${location.origin}/api/v1/demo-merchant/webhook`})});}else if(el.dataset.action==='edit-minimum-callback'){const asset=el.dataset.callbackAsset,value=prompt(`Minimum ${asset} callback amount`,data.projectSettings.minimum_callbacks?.[asset]||'0');if(value===null)return;await api('/api/v1/project-settings',{method:'POST',body:JSON.stringify({[`minimum_${asset.toLowerCase()}`]:value})});}else if(el.dataset.action==='toggle-withdrawal-verification'){await api('/api/v1/project-settings',{method:'POST',body:JSON.stringify({withdrawal_verification_enabled:!data.projectSettings.withdrawal_verification_enabled})});}else if(el.dataset.action==='toggle-project'){await api('/api/v1/project-settings',{method:'POST',body:JSON.stringify({enabled:!data.projectSettings.enabled})});}await loadData();toast(el.dataset.action==='use-demo-callback'?'Local merchant webhook receiver enabled':'Project settings updated');}catch(e){toast(`Settings update failed: ${e.message}`);}});

document.addEventListener('click',async event=>{const el=event.target.closest('[data-action="create-api-key"],[data-action="rotate-api-key"],[data-action="toggle-api-key"]');if(!el)return;try{if(el.dataset.action==='create-api-key'){const name=prompt('API key name','Merchant integration');if(!name)return;const record=await api('/api/v1/api-keys',{method:'POST',body:JSON.stringify({name,scopes:['payments:read','payments:write','withdrawals:read','withdrawals:write']})});await loadData();showApiKeySecret(record);return;}if(el.dataset.action==='rotate-api-key'){if(!confirm('Rotate this API key? The current secret will stop working immediately.'))return;const record=await api(`/api/v1/api-keys/${el.dataset.apiKeyId}/rotate`,{method:'POST',body:'{}'});await loadData();showApiKeySecret(record,'API key rotated');return;}const enabled=el.dataset.enabled==='true';if(!confirm(`${enabled?'Enable':'Disable'} this API key?`))return;await api(`/api/v1/api-keys/${el.dataset.apiKeyId}/status`,{method:'POST',body:JSON.stringify({enabled})});await loadData();toast(`API key ${enabled?'enabled':'disabled'}`);}catch(e){toast(`API key update failed: ${e.message}`);}});

document.addEventListener('click',async event=>{const el=event.target.closest('[data-action="deliver-callbacks"]');if(!el)return;try{const result=await api('/api/v1/callbacks/deliver-pending',{method:'POST',body:'{}'});await loadData();toast(`Callbacks delivered: ${result.delivered}; failed: ${result.failed}`);}catch(e){toast(`Callback delivery failed: ${e.message}`);}});

document.addEventListener('click',async event=>{const el=event.target.closest('[data-action="run-api-sample"]');if(el)await runApiSample(el.dataset.sample);});

document.addEventListener('click',async event=>{const el=event.target.closest('[data-action="add-address-book"]');if(!el)return;const listType=el.dataset.listType,asset=prompt('Asset (USDT or USDC)','USDT');if(!asset)return;const normalizedAsset=asset.trim().toUpperCase(),network=normalizedAsset==='USDC'?'POLYGON':'TRON',address=prompt(`${network} address`,'');if(!address)return;const alias=prompt('Address alias',listType==='ALLOWLIST'?'Approved recipient':'Blocked recipient');try{await api('/api/v1/address-book',{method:'POST',body:JSON.stringify({list_type:listType,asset:normalizedAsset,network,address:address.trim(),alias:alias||'Unnamed address'})});await loadData();toast(`${listType==='ALLOWLIST'?'Allowlist':'Blocklist'} entry added`);}catch(e){toast(`Address entry failed: ${e.message}`);}});

document.addEventListener('click',async event=>{const el=event.target.closest('[data-action="close-collection-detail"],[data-action="run-collection"],[data-action="toggle-collection"],[data-action="edit-collection-threshold"]');if(!el)return;
  if(el.dataset.action==='close-collection-detail'){ui.collectionItem='';render();return;}
  if(el.dataset.action==='run-collection'){try{const task=await api('/api/v1/collections/run',{method:'POST',body:JSON.stringify({network:el.dataset.network,asset:el.dataset.collectionAsset})});ui.collectionItem=task.id;await loadData();toast(`归集完成：${amount(task.amount)} ${task.asset}`);}catch(e){toast(`归集失败：${e.message}`);}return;}
  if(el.dataset.action==='toggle-collection'){try{await api('/api/v1/collection-policy',{method:'POST',body:JSON.stringify({enabled:!data.collectionPolicy.enabled})});await loadData();toast(data.collectionPolicy.enabled?'自动归集已恢复':'自动归集已暂停');}catch(e){toast(`策略修改失败：${e.message}`);}return;}
  if(el.dataset.action==='edit-collection-threshold'){const asset=el.dataset.collectionAsset,value=prompt(`请输入 ${asset} 归集阈值`,data.collectionPolicy.thresholds?.[asset]||'100');if(value!==null)try{await api('/api/v1/collection-policy',{method:'POST',body:JSON.stringify({[`threshold_${asset.toLowerCase()}`]:value})});await loadData();toast(`${asset} 归集阈值已更新`);}catch(e){toast(`阈值修改失败：${e.message}`);}return;}
});
document.addEventListener('click',async event=>{const el=event.target.closest('button,[data-asset],[data-wallet],[data-waas-item],[data-payment-item],[data-settlement-item],[data-transaction-item],[data-collection-item],[data-risk-detail],[data-role-detail]');if(!el)return;
  if(el.dataset.action==='approve-withdrawal'){try{await api(`/api/v1/withdrawals/${el.dataset.withdrawalId}/approve`,{method:'POST',body:'{}'});await loadData();toast('Finance approval completed; signing and broadcast status updated');}catch(e){toast(`Approval failed: ${e.message}`);}return;}
  if(el.dataset.action==='reject-withdrawal'){try{await api(`/api/v1/withdrawals/${el.dataset.withdrawalId}/reject`,{method:'POST',body:JSON.stringify({reason:'Rejected by finance review'})});ui.workflowItem='';await loadData();toast('Request rejected and recorded in the approval history');}catch(e){toast(`Rejection failed: ${e.message}`);}return;}
  if(el.dataset.module){ui.module=el.dataset.module;ui.page={wallet:'assets',workflow:'pending-approval',waas:'waas-payout',payment:'landing',transactions:'all',risk:'strategy',management:'subscription',market:'all',settings:'preference'}[ui.module];ui.walletDrawer='';ui.walletTx='';render();return;}
  if(el.dataset.action==='open-finance-approval'){ui.module='workflow';ui.page='pending-approval';ui.workflowItem=el.dataset.withdrawalId;render();return;}
  if(el.dataset.page){ui.page=el.dataset.page;ui.workflowItem='';ui.waasItem='';ui.paymentItem='';ui.settlementItem='';ui.transactionItem='';ui.collectionItem='';ui.riskDetail='';ui.roleDetail='';ui.accountDialog='';render();return;}if(el.dataset.wallet){ui.wallet=el.dataset.wallet;ui.page='assets';ui.walletDrawer='';render();return;}if(el.dataset.asset){ui.assetExpanded=ui.assetExpanded===el.dataset.asset?'':el.dataset.asset;render();return;}if(el.dataset.setting){ui.settingTab=el.dataset.setting;render();return;}if(el.dataset.paymentSetting){ui.paymentSettingTab=el.dataset.paymentSetting;render();return;}
  if(el.dataset.receiveCoin){ui.receiveCoin=el.dataset.receiveCoin;ui.receiveNetwork='';render();return;}if(el.dataset.receiveNetwork){ui.receiveNetwork=el.dataset.receiveNetwork;render();return;}if(el.dataset.sendCoin){ui.sendCoin=el.dataset.sendCoin;ui.sendNetwork='';render();return;}if(el.dataset.sendNetwork){ui.sendNetwork=el.dataset.sendNetwork;render();return;}if(el.dataset.walletTx!==undefined){ui.walletTx=el.dataset.walletTx;render();return;}if(el.dataset.workflowItem){ui.workflowItem=el.dataset.workflowItem;render();return;}if(el.dataset.waasItem){ui.waasItem=el.dataset.waasItem;render();return;}if(el.dataset.paymentItem){ui.paymentItem=el.dataset.paymentItem;render();return;}if(el.dataset.settlementItem){ui.settlementItem=el.dataset.settlementItem;render();return;}if(el.dataset.transactionItem){ui.transactionItem=el.dataset.transactionItem;render();return;}if(el.dataset.collectionItem){ui.collectionItem=el.dataset.collectionItem;render();return;}if(el.dataset.riskDetail){ui.riskDetail=el.dataset.riskDetail;render();return;}if(el.dataset.roleDetail){ui.roleDetail=el.dataset.roleDetail;render();return;}if(el.dataset.accountDialog){ui.accountDialog=el.dataset.accountDialog;render();return;}if(el.dataset.copy){navigator.clipboard?.writeText(el.dataset.copy);toast('演示地址已复制');return;}
  if(el.dataset.simulatePayment){try{const payload=el.dataset.paidAmount?{paid_amount:el.dataset.paidAmount}:{};await api(`/api/v1/payment-orders/${el.dataset.simulatePayment}/simulate-confirm`,{method:'POST',body:JSON.stringify(payload)});if(document.getElementById('actionDialog')?.open)document.getElementById('actionDialog').close();ui.paymentItem=el.dataset.simulatePayment;await loadData();toast('Payment received and order status updated');}catch(e){toast(`Payment simulation failed: ${e.message}`);}return;}
  if(el.dataset.expirePayment){try{await api(`/api/v1/payment-orders/${el.dataset.expirePayment}/simulate-expire`,{method:'POST',body:'{}'});ui.paymentItem=el.dataset.expirePayment;await loadData();toast('Payment order marked as expired');}catch(e){toast(`Expiry simulation failed: ${e.message}`);}return;}
  if(el.dataset.previewCheckout){paymentCheckoutDialog(el.dataset.previewCheckout);return;}
  if(el.dataset.action==='send'){ui.page='wallet-send';ui.sendCoin='';ui.sendNetwork='';render();return;}if(el.dataset.action==='receive'){ui.page='wallet-receive';ui.receiveCoin='';ui.receiveNetwork='';render();return;}if(el.dataset.action==='addresses'){ui.walletDrawer='addresses';render();return;}if(el.dataset.action==='wallet-back'||el.dataset.action==='wallet-assets'){ui.page='assets';ui.walletDrawer='';ui.walletTx='';render();return;}if(el.dataset.action==='wallet-transactions'){ui.page='wallet-transactions';ui.walletDrawer='';render();return;}if(el.dataset.action==='close-wallet-drawer'){ui.walletDrawer='';render();return;}if(el.dataset.action==='close-tx-drawer'){ui.walletTx='';render();return;}if(el.dataset.action==='close-global-transaction'){ui.transactionItem='';render();return;}if(el.dataset.action==='close-workflow-drawer'){ui.workflowItem='';render();return;}if(el.dataset.action==='close-waas-detail'){ui.waasItem='';render();return;}if(el.dataset.action==='close-payment-detail'){ui.paymentItem='';render();return;}if(el.dataset.action==='close-payment-settlement'){ui.settlementItem='';render();return;}if(el.dataset.action==='close-risk-detail'){ui.riskDetail='';render();return;}if(el.dataset.action==='close-role-detail'){ui.roleDetail='';render();return;}if(el.dataset.action==='close-account-dialog'){ui.accountDialog='';render();return;}if(el.dataset.action==='receive-reset-coin'){ui.receiveCoin='';ui.receiveNetwork='';render();return;}if(el.dataset.action==='receive-reset-network'){ui.receiveNetwork='';render();return;}if(el.dataset.action==='send-reset-coin'){ui.sendCoin='';ui.sendNetwork='';render();return;}if(el.dataset.action==='send-reset-network'){ui.sendNetwork='';render();return;}if(el.dataset.action==='demo-send-inline'){const toAddress=document.getElementById('sendAddress')?.value.trim(),sendAmount=document.getElementById('sendAmount')?.value.trim(),network=ui.sendNetwork==='Polygon'?'POLYGON':ui.sendNetwork.toUpperCase();if(!toAddress||!sendAmount){toast('请填写接收方地址和金额');return;}try{await api('/api/v1/withdrawals',{method:'POST',body:JSON.stringify({merchant_withdraw_id:`M2-WALLET-${Date.now()}`,merchant:ui.wallet,user_id:currentUser.username,amount:sendAmount,currency:ui.sendCoin,network,to_address:toAddress})});ui.module='workflow';ui.page='pending-approval';ui.workflowItem='';await loadData();toast('转账申请已创建，等待财务审批');}catch(e){toast(`创建失败：${e.message}`);}return;}if(el.dataset.action==='create-payment')createPaymentDialog();if(el.dataset.action==='close-dialog')document.getElementById('actionDialog').close();if(el.dataset.action==='demo-send'){document.getElementById('actionDialog').close();ui.module='workflow';ui.page='pending-approval';render();toast('Demo：转账申请已进入财务审批队列');}
  if(el.dataset.retry){try{await api(`/api/v1/callbacks/${el.dataset.retry}/retry`,{method:'POST',body:'{}'});await loadData();toast('异常回调已重新推送');}catch(e){toast(`推送失败：${e.message}`);}}
  if(el.dataset.action==='toggle-payout'){try{await api('/api/v1/risk-policy',{method:'POST',body:JSON.stringify({payouts_enabled:!data.riskPolicy.payouts_enabled})});await loadData();toast(data.riskPolicy.payouts_enabled?'出款已恢复':'所有新出款已暂停');}catch(e){toast(`策略修改失败：${e.message}`);}}
  if(el.dataset.action==='edit-limit'){const value=prompt('请输入新的单笔出款限额',data.riskPolicy.max_withdrawal_amount);if(value!==null)try{await api('/api/v1/risk-policy',{method:'POST',body:JSON.stringify({max_withdrawal_amount:value})});await loadData();toast('单笔出款限额已更新');}catch(e){toast(`限额修改失败：${e.message}`);}}
  if(el.dataset.action==='toggle-allowlist'){try{await api('/api/v1/risk-policy',{method:'POST',body:JSON.stringify({allowlist_enforced:!data.riskPolicy.allowlist_enforced})});await loadData();toast(data.riskPolicy.allowlist_enforced?'Recipient allowlist enforcement enabled':'Recipient allowlist enforcement disabled');}catch(e){toast(`Allowlist policy update failed: ${e.message}`);}}
  if(el.dataset.action==='edit-daily-limit'){const value=prompt('Daily stablecoin payout limit',data.riskPolicy.daily_withdrawal_limit);if(value!==null)try{await api('/api/v1/risk-policy',{method:'POST',body:JSON.stringify({daily_withdrawal_limit:value})});await loadData();toast('Daily payout limit updated');}catch(e){toast(`Daily limit update failed: ${e.message}`);}}
  if(el.dataset.action==='edit-network-reserve'){const reserve=(data.networkReserves||[]).find(r=>r.network===el.dataset.network);if(!reserve)return;const available=prompt(`${reserve.network} 可用 ${reserve.native_asset} 余额`,reserve.available);if(available===null)return;const minimum=prompt(`${reserve.network} 最低保留 ${reserve.native_asset}`,reserve.minimum_required);if(minimum===null)return;const estimate=prompt(`${reserve.network} 单笔预估 ${reserve.native_asset}`,reserve.estimated_per_transaction);if(estimate===null)return;try{await api('/api/v1/network-reserves',{method:'POST',body:JSON.stringify({network:reserve.network,available,minimum_required:minimum,estimated_per_transaction:estimate})});await loadData();toast(`${reserve.network} network fee reserve updated`);}catch(e){toast(`Reserve update failed: ${e.message}`);}return;}
  if(el.dataset.action==='refresh-readiness'){await loadData();toast('Acceptance evidence refreshed');}
  if(el.dataset.action==='logout'){try{await api('/api/v1/session/logout',{method:'POST',body:'{}'});}finally{currentUser=null;showLogin('已安全退出');}}
});
document.addEventListener('submit',async event=>{if(event.target.id==='loginForm'){event.preventDefault();const f=new FormData(event.target);document.getElementById('loginError').textContent='';try{const user=await api('/api/v1/session',{method:'POST',body:JSON.stringify({username:f.get('username'),password:f.get('password')})});enterApp(user);await loadData();}catch(e){showLogin(e.message);}return;}if(event.target.id!=='paymentCreateForm')return;event.preventDefault();const f=new FormData(event.target),[currency,network]=String(f.get('pair')).split('|');try{await api('/api/v1/payment-orders',{method:'POST',body:JSON.stringify({merchant_order_id:f.get('merchant_order_id'),merchant:f.get('merchant'),customer_id:f.get('customer_id'),return_url:f.get('return_url'),amount:f.get('amount'),order_currency:'USD',pay_currency:currency,network,metadata:{source:'m2-sandbox-ui'}})});document.getElementById('actionDialog').close();await loadData();toast('支付订单已创建并生成收款地址');}catch(e){toast(`创建失败：${e.message}`);}});
function riskStrategyPage(){const policy=data.riskPolicy||{};const limit=Number(policy.max_withdrawal_amount||0).toLocaleString('zh-CN',{maximumFractionDigits:6});return `<section class="page"><div class="toolbar"><h1>策略</h1><span class="status ${policy.broadcast_mode==='simulation'?'pending':''}">${policy.broadcast_mode==='simulation'?'模拟资金模式':'RPC 广播模式'}</span></div><div class="card-grid"><div class="card"><h3>总出款开关</h3><p>关闭后，所有新的财务审批都会在签名前被阻止。</p><strong class="metric">${policy.payouts_enabled?'已开启':'已暂停'}</strong>${roleCan('ADMIN')?`<button class="btn ${policy.payouts_enabled?'danger':'primary'}" data-action="toggle-payout">${policy.payouts_enabled?'立即暂停':'恢复出款'}</button>`:''}</div><div class="card"><h3>单笔出款限额</h3><p>应用于钱包发送与 WaaS API 提币。</p><strong class="metric">${limit} USDT</strong>${roleCan('ADMIN')?'<button class="btn" data-action="edit-limit">编辑限额</button>':''}</div><div class="card"><h3>财务审批</h3><p>只有 FINANCE 与 ADMIN 可以批准或拒绝提现。</p><strong class="metric">必须</strong></div><div class="card"><h3>审批审计</h3><p>记录审批人、业务单、结果、时间与失败原因。</p><strong class="metric">已启用</strong></div></div></section>`;}
function riskStrategyPageV2(){const policy=data.riskPolicy||{},limit=Number(policy.max_withdrawal_amount||0).toLocaleString('zh-CN',{maximumFractionDigits:6}),dailyLimit=Number(policy.daily_withdrawal_limit||0).toLocaleString('zh-CN',{maximumFractionDigits:6}),dailyUsed=Number(policy.daily_withdrawn_amount||0).toLocaleString('zh-CN',{maximumFractionDigits:6}),reserves=data.networkReserves||[],healthy=reserves.filter(r=>r.healthy).length;const rules=[{id:'single',name:'单笔发送限额',scope:'发送交易 · 人工转出 · API 提币',condition:`Amount > ${limit} USDT`,action:'Block payout before signing',state:policy.payouts_enabled?'已启用':'未开启'},{id:'whitelist',name:'白名单校验',scope:'所有钱包与 WaaS 项目',condition:'Recipient is not allowlisted',action:'Block withdrawal creation',state:policy.allowlist_enforced?'已启用':'未开启'},{id:'daily',name:'单日累计发送',scope:'All stablecoin payouts',condition:`Daily total > ${dailyLimit} USD`,action:'Block payout before signing',state:`${dailyUsed} / ${dailyLimit} used`},{id:'network-fee',name:'链上手续费储备',scope:'TRON USDT · Polygon USDC',condition:'Projected transactions < 1 above reserve floor',action:'Block approval before signing',state:`${healthy} / ${reserves.length||2} networks healthy`}];return `<section class="page risk-native-page"><div class="toolbar"><h1>策略</h1><div><span class="status pending">${policy.broadcast_mode==='simulation'?'模拟资金模式':'RPC 广播模式'}</span> <button class="btn primary">＋ 新增策略</button></div></div><div class="risk-native-list">${rules.map(r=>`<div class="risk-native-row" data-risk-detail="${r.id}"><span class="risk-symbol">◇</span><div><b>${r.name}</b><small>${r.scope}</small></div><div><small>条件</small><b>${r.condition}</b></div><div><small>执行动作</small><b>${r.action}</b></div><span class="status ${r.id==='network-fee'&&healthy<reserves.length?'failed':''}">${r.state}</span></div>`).join('')}</div><div class="risk-quick"><button class="btn ${policy.payouts_enabled?'danger':'primary'}" data-action="toggle-payout">${policy.payouts_enabled?'暂停全部出款':'恢复全部出款'}</button>${roleCan('ADMIN')?`<button class="btn" data-action="edit-limit">Edit single limit</button><button class="btn ${policy.allowlist_enforced?'danger':''}" data-action="toggle-allowlist">${policy.allowlist_enforced?'Disable allowlist':'Enable allowlist'}</button><button class="btn" data-action="edit-daily-limit">Edit daily limit</button>`:''}</div>${ui.riskDetail?riskDetailDrawer(rules.find(r=>r.id===ui.riskDetail)):''}</section>`;}
function riskDetailDrawer(r){if(!r)return'';return `<aside class="wallet-drawer risk-drawer"><button class="drawer-close" data-action="close-risk-detail">×</button><h2>${r.name}</h2><div class="settings-field"><small>策略状态</small><strong>${r.state}</strong></div><h3>基础设置</h3><div class="settings-field"><small>策略类型</small><strong>${r.scope}</strong></div><div class="settings-field"><small>决策条件</small><strong>${r.condition}</strong></div><div class="settings-field"><small>命中方式</small><strong>全部命中</strong></div><h3 class="settings-divider">执行动作</h3><div class="settings-field"><small>动作</small><strong>${r.action}</strong></div><h3 class="settings-divider">审批流程</h3><div class="approval-progress"><p><i></i><b>发起人</b><span>任意成员</span></p><p><i></i><b>财务审批</b><span>FINANCE / ADMIN</span></p><p><i></i><b>签名</b><span>M2 签名服务</span></p></div><button class="btn primary">编辑策略</button></aside>`;}
function automationPageV2(){const policy=data.collectionPolicy||{},candidates=data.collectionCandidates||[],tasks=data.collections||[],reserves=data.networkReserves||[],feeEvents=data.networkFeeEvents||[],jobs=[{id:'collect',name:'自动归集',desc:'支付子地址达到阈值后归集至 M2 主钱包',state:policy.enabled?'运行中':'已暂停',mode:`USDT ≥ ${policy.thresholds?.USDT||100} · USDC ≥ ${policy.thresholds?.USDC||100}`},{id:'sign',name:'自动签名',desc:'审批完成后由独立签名服务完成签名',state:'运行中',mode:'财务审批通过后执行'}];return `<section class="page automation-page"><div class="toolbar"><h1>自动化</h1><div><span class="status ${policy.enabled?'':'failed'}">归集${policy.enabled?'运行中':'已暂停'}</span>${roleCan('ADMIN')?` <button class="btn" data-action="toggle-collection">${policy.enabled?'暂停归集':'恢复归集'}</button>`:''}</div></div><div class="risk-native-list">${jobs.map(j=>`<div class="risk-native-row automation-row" data-risk-detail="${j.id}"><span class="risk-symbol">↻</span><div><b>${j.name}</b><small>${j.desc}</small></div><div><small>触发条件</small><b>${j.mode}</b></div><span class="status ${j.state==='已暂停'?'failed':''}">${j.state}</span></div>`).join('')}</div><div class="collection-section network-reserve-section"><div class="section-title"><h2>链上手续费储备</h2><small>财务审批前实时校验，成功广播或归集后自动扣减</small></div><div class="network-reserve-grid">${reserves.map(r=>`<article class="network-reserve-card ${r.healthy?'healthy':'critical'}"><div class="reserve-head"><span class="network-mark">${r.network==='TRON'?'◆':'⬡'}</span><div><b>${esc(r.network)}</b><small>${esc(r.label)}</small></div><span class="status ${r.healthy?'':'failed'}">${r.healthy?'Healthy':'Action required'}</span></div><strong>${amount(r.available)} ${esc(r.native_asset)}</strong><div class="reserve-meter"><i style="width:${Math.min(100,Math.max(4,Number(r.available)/(Number(r.minimum_required)+Number(r.estimated_per_transaction))*55))}%"></i></div><div class="reserve-stats"><span><small>最低保留</small>${amount(r.minimum_required)} ${esc(r.native_asset)}</span><span><small>单笔预估</small>${amount(r.estimated_per_transaction)} ${esc(r.native_asset)}</span><span><small>预计可处理</small>${r.projected_transactions} 笔</span></div><footer><small>Updated ${time(r.updated_at)} by ${esc(r.updated_by)}</small>${roleCan('ADMIN')?`<button class="btn" data-action="edit-network-reserve" data-network="${r.network}">更新储备</button>`:''}</footer></article>`).join('')}</div></div><div class="collection-section fee-events-section"><div class="section-title"><h2>手续费流水</h2><small>提现与归集的链上手续费预留、消耗和释放记录</small></div>${feeEvents.length?`<div class="fee-event-list">${feeEvents.slice(0,8).map(e=>`<div class="fee-event-row"><span class="network-mark">${e.network==='TRON'?'◆':'⬡'}</span><div><b>${esc(e.reference_type)} · ${short(e.reference_id,13,6)}</b><small>${esc(e.network)} · ${time(e.updated_at)} · ${esc(e.actor)}</small></div><strong>−${amount(e.amount)} ${esc(e.native_asset)}<small class="fee-state ${e.status.toLowerCase()}">${esc(e.status)}</small></strong></div>`).join('')}</div>`:empty('暂无手续费流水')}</div><div class="collection-section"><div class="section-title"><h2>待归集资产</h2><small>来自已确认且尚未归集的支付地址</small></div>${candidates.length?`<div class="collection-candidates">${candidates.map(c=>`<div class="collection-candidate"><span>${coinMark(c.asset)}</span><div><b>${c.asset}-${c.network}</b><small>${c.source_count} 个支付地址 · 阈值 ${amount(c.threshold)} ${c.asset}</small></div><strong>${amount(c.amount)} ${c.asset}<small>${c.eligible?'达到归集条件':'尚未达到阈值'}</small></strong>${c.eligible&&roleCan('ADMIN','OPERATOR')?`<button class="btn primary" data-action="run-collection" data-network="${c.network}" data-collection-asset="${c.asset}">立即归集</button>`:''}</div>`).join('')}</div>`:empty('暂无待归集资产')}</div><div class="collection-section"><div class="section-title"><h2>归集记录</h2><small>${tasks.length} 个任务</small></div>${tasks.length?`<div class="waas-native-list">${tasks.map(t=>`<div class="waas-native-row collection-task-row" data-collection-item="${t.id}"><span class="callback-icon">⇄</span><span><b>${t.asset}-${t.network} ${status(t.status)}</b><small>${t.source_count} 个地址 → ${short(t.destination_address,12,8)}</small></span><strong>${amount(t.amount)} ${t.asset}<small>${time(t.updated_at)}</small></strong></div>`).join('')}</div>`:empty('暂无归集记录')}</div>${ui.riskDetail?automationDrawer(jobs.find(j=>j.id===ui.riskDetail)):''}${ui.collectionItem?collectionTaskDrawer(tasks.find(t=>t.id===ui.collectionItem)):''}</section>`;}
function automationDrawer(j){if(!j)return'';const collection=j.id==='collect',policy=data.collectionPolicy||{};return `<aside class="wallet-drawer risk-drawer"><button class="drawer-close" data-action="close-risk-detail">×</button><h2>${j.name}</h2><div class="settings-field"><small>状态</small><strong>${j.state}</strong></div><div class="settings-field"><small>触发条件</small><strong>${j.mode}</strong></div><div class="settings-field"><small>执行项目</small><strong>M2 收付项目</strong></div><div class="settings-field"><small>目标钱包</small><strong>M2 主钱包</strong></div>${collection?`<div class="settings-field"><small>TRON 目标地址</small><strong>${short(policy.destinations?.TRON||'',12,8)}</strong></div><div class="settings-field"><small>Polygon 目标地址</small><strong>${short(policy.destinations?.POLYGON||'',12,8)}</strong></div>${roleCan('ADMIN')?`<button class="btn" data-action="edit-collection-threshold" data-collection-asset="USDT">修改 USDT 阈值</button> <button class="btn" data-action="edit-collection-threshold" data-collection-asset="USDC">修改 USDC 阈值</button>`:''}`:''}<div class="setting-row"><div><strong>启用规则</strong><small>关闭后停止创建新的自动任务</small></div><span class="switch ${j.state==='运行中'?'on':''}"></span></div></aside>`;}
function collectionTaskDrawer(t){if(!t)return'';return `<aside class="wallet-drawer risk-drawer"><button class="drawer-close" data-action="close-collection-detail">×</button><h2>归集详情</h2><div class="waas-amount"><span>${status(t.status)}</span><h2>${amount(t.amount)} ${t.asset}</h2></div><div class="tx-fields"><label>任务编号<strong>${esc(t.id)}</strong></label><label>网络<strong>${esc(t.network)}</strong></label><label>来源地址<strong>${t.source_count} 个支付子地址</strong></label><label>目标钱包<strong>M2 主钱包</strong></label><label>目标地址<strong>${esc(t.destination_address)}</strong></label><label>触发人<strong>${esc(t.triggered_by)}</strong></label><label>创建时间<strong>${time(t.created_at)}</strong></label><label>完成时间<strong>${t.status==='CONFIRMED'?time(t.updated_at):'—'}</strong></label><label>交易哈希<strong>${t.tx_hash||'尚未生成'}</strong></label></div></aside>`;}

function rolesPageV2(){const roles=[{id:'super',name:'超级管理员',members:1,desc:'拥有团队全部权限'},{id:'admin',name:'管理员',members:1,desc:'按模块分配管理权限'},{id:'finance',name:'财务审批',members:1,desc:'查看钱包并处理审批'},{id:'viewer',name:'普通成员',members:1,desc:'仅查看获授权的数据'}];return `<section class="page roles-page"><div class="toolbar"><h1>角色</h1><button class="btn primary">新增角色</button></div><div class="role-native-list">${roles.map(r=>`<div class="role-native-row" data-role-detail="${r.id}"><span class="role-icon">♧</span><div><b>${r.name}</b><small>${r.desc}</small></div><strong>${r.members} 人</strong><span>›</span></div>`).join('')}</div>${ui.roleDetail?rolePermissionDrawer(roles.find(r=>r.id===ui.roleDetail)):''}</section>`;}
function rolePermissionDrawer(r){if(!r)return'';const groups=[['钱包',['查看钱包','创建钱包','发送交易','管理地址']],['协作',['查看待办','审批交易','签名交易']],['WaaS 项目',['查看项目','API 提币','回调管理','项目设置']],['支付引擎',['查看订单','创建订单','结算设置']],['风控与管理',['查看策略','管理自动化','成员与角色','团队 API']]];return `<aside class="wallet-drawer role-drawer"><button class="drawer-close" data-action="close-role-detail">×</button><h2>${r.name}</h2><p>${r.desc}</p><div class="permission-summary"><span>${r.members} 名成员</span><button class="btn">管理成员</button></div><h3>权限</h3>${groups.map(([name,items])=>`<div class="permission-group"><b>${name}</b>${items.map((x,i)=>`<label><input type="checkbox" ${r.id==='super'||(r.id==='finance'&&['查看钱包','查看待办','审批交易','查看订单'].includes(x))?'checked':''} ${r.id==='super'?'disabled':''}/>${x}</label>`).join('')}</div>`).join('')}<button class="btn primary role-save">保存权限</button></aside>`;}

function auditPage(){return `<section class="page"><div class="toolbar"><h1>审计日志</h1><button class="btn">筛选</button></div><table class="data-table"><thead><tr><th>时间</th><th>成员</th><th>角色</th><th>事件</th><th>对象</th><th>结果</th><th>详情</th></tr></thead><tbody>${data.auditLogs.map(a=>`<tr><td>${time(a.created_at)}</td><td>${esc(a.actor)}</td><td>${esc(a.role)}</td><td>${esc(a.action)}</td><td>${esc(a.resource_type)}<span class="cell-sub">${esc(a.resource_id||'—')}</span></td><td>${status(a.outcome==='SUCCESS'?'CONFIRMED':a.outcome==='DENIED'?'REJECTED':'FAILED')}</td><td>${esc(a.detail||'—')}</td></tr>`).join('')}</tbody></table>${data.auditLogs.length?'':empty('暂无审计记录')}</section>`;}

function accountSettingsPage(){const p=ui.page||'preference';if(p==='account-security')return `<section class="page"><div class="toolbar"><h1>账号安全</h1></div>${[['身份认证','内部试用账号由管理员预设','已配置'],['登录密码','用于登录 M2 Wallet','已设置'],['会话保护','8 小时后自动失效','已开启'],['锁屏保护','暂时离开设备时隐藏业务数据','开启']].map(x=>`<div class="setting-row"><div><strong>${x[0]}</strong><small>${x[1]}</small></div><button class="btn">${x[2]}</button></div>`).join('')}</section>`;if(p==='mpc-network')return `<section class="page"><div class="toolbar"><h1>MPC网络</h1></div><div class="card-grid"><div class="card"><h3>独立签名服务</h3><p>应用只发送交易意图，不保存原始私钥。</p><strong class="metric">模拟连接</strong></div><div class="card"><h3>签名节点</h3><p>内部试用阶段使用不可花费资产的模拟签名器。</p><strong class="metric">1 / 1</strong></div></div></section>`;if(p==='about')return `<section class="page"><div class="toolbar"><h1>关于 M2 Wallet</h1></div><div class="card"><h3>M2 Wallet Internal Trial</h3><strong class="metric">0.3.0</strong><p>稳定币钱包、支付引擎、WaaS 提币、协作审批与风控平台。</p></div></section>`;return `<section class="page"><div class="toolbar"><h1>偏好设置</h1></div><div class="account-card"><div class="account-profile"><span class="avatar-large">${currentUser.username.slice(0,1).toUpperCase()}</span><div><strong>${esc(currentUser.display_name)}</strong><small>${esc(currentUser.username)} · ${esc(currentUser.role)}</small></div></div><div class="setting-row"><div><strong>语言</strong><small>界面显示语言</small></div><button class="btn">简体中文</button></div><div class="setting-row"><div><strong>货币单位</strong><small>资产估值单位</small></div><button class="btn">美元</button></div><div class="setting-row"><div><strong>外观</strong><small>当前使用浅色主题</small></div><button class="btn">浅色</button></div><div class="setting-row"><div><strong>提示音</strong><small>收到审批与异常消息时播放</small></div><span class="switch on"></span></div><button class="btn danger" data-action="logout" style="margin-top:25px">退出登录</button></div></section>`;}
function accountSettingsPageV2(){if(ui.page!=='account-security')return accountSettingsPage();const rows=[['identity','身份认证','内部试用账号由管理员预设','已配置'],['password','登录密码','用于登录 M2 Wallet','修改'],['session','登录设备','管理当前账号的有效会话','1 台设备'],['lock','锁屏保护','暂时离开设备时隐藏业务数据','开启']];return `<section class="page account-security-page"><div class="toolbar"><h1>账号安全</h1></div>${rows.map(x=>`<div class="setting-row"><div><strong>${x[1]}</strong><small>${x[2]}</small></div><button class="btn" data-account-dialog="${x[0]}">${x[3]}</button></div>`).join('')}${ui.accountDialog?accountSecurityDrawer(ui.accountDialog):''}</section>`;}
function accountSecurityDrawer(type){const map={identity:['身份认证','当前为 M2 Wallet 内部试用账号，身份由团队管理员统一配置。'],password:['修改登录密码','输入当前密码和新密码，保存后其他设备会话将失效。'],session:['登录设备','当前设备 · macOS · 本地演示环境 · 活跃'],lock:['锁屏保护','开启后离开页面时可快速隐藏钱包、订单和审批数据。']};const [title,desc]=map[type]||map.identity;return `<aside class="wallet-drawer account-drawer"><button class="drawer-close" data-action="close-account-dialog">×</button><h2>${title}</h2><p>${desc}</p>${type==='password'?`<div class="secure-form"><label>当前密码<input type="password" placeholder="输入当前密码"/></label><label>新密码<input type="password" placeholder="至少 10 位"/></label><label>确认新密码<input type="password" placeholder="再次输入"/></label><button class="btn primary">保存</button></div>`:type==='session'?`<div class="session-device"><b>当前设备</b><span class="status">在线</span><small>macOS · 127.0.0.1 · 当前会话</small><button class="btn">退出其他设备</button></div>`:`<div class="setting-row"><div><strong>${title}</strong><small>${desc}</small></div><span class="switch on"></span></div>`}</aside>`;}

